INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2025년 연간기부금 모금액 활용실적 명세서','<2025 년도 기부금 모금액 및 활용실적 보고 > 기부금 모금 기간 : 2025. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2025. 01. 01. ~ 12. 31. [ 보고 근거 ] - 우리 포럼은 ','<2025 년도 기부금 모금액 및 활용실적 보고 > 기부금 모금 기간 : 2025. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2025. 01. 01. ~ 12. 31. [ 보고 근거 ] - 우리 포럼은 기획재정부장관이 지정한 지정기부금단체입니다 . - 또한 사단법인 동북아공동체 ICT 포럼 정관 제 21 조 제 2 항 ( 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음연도 3 월말까지 공개한다 ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . [ 기부금 수입 ] * 수입총액 : 16,400,000 원 [ 기부금 지출 ] * 지출총액 : 16,400,000 원 a. 조찬간담회 행사비용 외 : 16,400,000','2026-02-09','','2025_연간기부금 모금액 및 활용실적 명세서.pdf [242KB]','',1,101,'2026-02-09 00:00:00','2026-02-09 00:00:00');
