INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','포럼 유튜브 시청요청','유튜브 검색창에 "동북아공동체ict포럼"을 검색하시면 (재)통일과나눔 후원으로 우리 포럼이 실시한 "통일ICT전문가 아카데미" 교육 동영상 20여개를 볼 수 있습니다. 한반도 정세와 북한의 경제, 북한의 ICT기술수','유튜브 검색창에 "동북아공동체ict포럼"을 검색하시면 (재)통일과나눔 후원으로 우리 포럼이 실시한 "통일ICT전문가 아카데미" 교육 동영상 20여개를 볼 수 있습니다. 한반도 정세와 북한의 경제, 북한의 ICT기술수준(최근 탈북 북한 IT점누가 강의), 북한지역 핀테크, 원격의료, 북한 스포츠 방송, 북한의 신재생 에너지 기술현황과 가정용 태양광 패널 실태, 북한의 게임산업 및 디지털 기술을 활용한 북한관련 콘텐츠 제작에 대해 국내 최고의 전문가의 강의를 보시고 좋아요, 구독을 눌러주세요. 제 1강 : 한반도정세와 통일 준비 (손기웅 전 통일연구원 원장) https://youtu.be/S4rNmI80IxQ https://youtu.be/bu7odi9d7f0 제 2강 : 최근 북한의 경제 동향 및 전망 (김영수 서강대학교 명예교수) https://youtu.be/w15_hC7dS-o https://youtu.be/ANhW20-b1wM 제 3강 : 북한의 ICT기술수준과 미래 (장혁 전 북한과학교육부 엔지니어) https://youtu.be/Ief3RQSCbTQ https://youtu.be/qULz8xD7hzE 제 4강 : 북한지역 핀테크 활용현황과 발전전망 (박기찬 신한은행 북한연구회 회장) https://youtu.be/RYOYYiJKMEM https://youtu.be/-LCOrataM7c 제 5강 : 원격의료를 활용한 한반도 건강공동체 준비 (김신곤 고려대학교 의과대학 교수) https://youtu.be/FsMEb8EA2mA https://youtu.be/B7qqB_TbSCk 제 6강 : 북한 스포츠 방송현황과 남북 스포츠 방송교류 (성문정 한국스포츠정책과학원 수석연구위원) https://youtu.be/-Nt7W9sM8J4 https://youtu.be/Lh7zKZJwq4Q 제 7강 : 북한 신재생에너지 기술개발현황과 가정용 태양광패널 이용실태 (신정수 에너지경제연구원 연구위원) https://youtu.be/sBKIbMj-CZE https://youtu.be/k1MBgZRRbqE 제 8강 : 북한의 게임산업 : 기술과 문화의 혼종과 융합 (이지순 통일연구원 연구위원) https://youtu.be/nLyCd8g5Kr8 제 9강 : 비즈니스 시뮬레이션 (조성갑 안양대학교 석좌교수) https://youtu.be/FwzkDEZ9bko 제10강 : ICT기술과 접목한 남북교류 콘텐츠 제작사례 (김명환 주식회사 부뚜막고양이 대표) https://youtu.be/ioewaLBFAZ8 https://youtu.be/yuZHw6jMT08','2025-01-08','','','',1,94,'2025-01-08 00:00:00','2025-01-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[독서모임] 제9회 독서모임 결과 보고','2024.12.26(목) 19시~21시에 조성갑 교수님 외 9명의 포럼 회원들이 역삼동 대명빌딩 401호에서 박종훈 저. <트럼프 2.0시대>라는 책을 주제으로 독서모임을 가졌습니다. 구교광 부회장님의 시간과 세월을','2024.12.26(목) 19시~21시에 조성갑 교수님 외 9명의 포럼 회원들이 역삼동 대명빌딩 401호에서 박종훈 저. <트럼프 2.0시대>라는 책을 주제으로 독서모임을 가졌습니다. 구교광 부회장님의 시간과 세월을 주제로 한 세 편의 시(토마스 그레이의 시골 교회의 묘지에서 쓴 만 가, 사무엘 울만 의 청춘, 신석정의 소곡) 낭독으로 시작된 독서모임은 <트럼프 2.0시대>에 대한 정 종광 트리세스네트웍스 대표님의 발표를 통해 차기 트럼프 행정부의 관세정책과 우리의 대응방안에 대해 더 자세히 알 수 있는 유익한 시간이었습니다. 또한 독서모임 후 뒷풀이를 통해 회원 간에 관계를 돈독하게 할 수 있는 시간도 마련 되었습니다. 차기 제10회 독서모임은 2025.1.23 (목) 19시~21시에 같은 장소인 역삼동 대명빌딩 401호에서 진행되오니 관심있는 포럼 회원분들의 많은 참여 부탁드립니다. *1월의 도서:"넥서스(유발 하라리 저)" 김우헌 - 한국기술사회 CMP우원회 위원장님 발표 애송시 소개:김홍용 대표','2024-12-27','','','',1,93,'2024-12-27 00:00:00','2024-12-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 89차 석찬 세미나 참석 요청','[제89차 석찬 세미나 참석 요청] 그간 안녕하십니까? 금년 연말이 어느덧 50여일 앞으로 성큼 다가 왔습니다. 이번 12월 세미나는 조금 시간적 여유를 가지고 신규 회원사 솔루션 소개와 행사 후 식사와 친교 시간을','[제89차 석찬 세미나 참석 요청] 그간 안녕하십니까? 금년 연말이 어느덧 50여일 앞으로 성큼 다가 왔습니다. 이번 12월 세미나는 조금 시간적 여유를 가지고 신규 회원사 솔루션 소개와 행사 후 식사와 친교 시간을 가지기 위하여 석찬 행사로 준비하고자 하오니 바쁘시더라도 많은 참가신청 바랍니다. ▶ 일 시 : 2024년 12월 17일(화) - 17:00 ~ 18:00 회원사 솔루션 소개 - 18:00 ~ 19:00 명사 초청 강연: 태영호 민주 평화통일자문회의 사무처장 (전 국회의원. 전 영국 주재 북한공사) (가칭) 트럼프 2.0시대 남북관계 전망 및 대응 전략 - 19:00 ~ 20:30 인근 음식점 식사 및 친교 ▶ 장 소 : 대치 열린 학습관 5층 대 강당 (서울시 강남구 영동대로 57길 7 대치동) (Tel. 02-2176-0851) - 지하철 3호선 학여울역 1번 출구 삼성 스토어 방향 도보 10분. 지하철 2호선 3번출구 강남 01,06 마을버스 등 10분 ▶ 참가비 : 6만원 / [개인회원 30만원 이상, 기관회원 100만원, 기업회원 200만원 이상 년회비 납부하신 분은 무료] - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 참가신청 방법 : 이메일이나 문자 회신,포럼 단체 카톡방이나 전화 신청 (소속.직위. 핸드폰 번호) ▶문의처 : 010-2378-2060 (구교광 부회장 / bismak0308@naver.com ) (사)동북아공동체ICT포럼 석호익 회장 올림','2024-11-14','','','',1,92,'2024-11-14 00:00:00','2024-11-14 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[독서모임] 제6회 독서모임 결과 보고','2024.09.04(수) 19시~21시에 석호익 회장님 외 13명의 포럼 회원들이 역삼동 대명빌딩 401호에서 <나는 인공지능을 변호한다>라는 책을 주제으로 독서모임을 가졌습니다. 권준철 부사장님의 애송시, 자작시 ','2024.09.04(수) 19시~21시에 석호익 회장님 외 13명의 포럼 회원들이 역삼동 대명빌딩 401호에서 <나는 인공지능을 변호한다>라는 책을 주제으로 독서모임을 가졌습니다. 권준철 부사장님의 애송시, 자작시 소개와 낭송으로 시작된 독서모임은 <나는 인공지능을 변호한다>의 저자이신 이상직 변호사님의 발표를 통해 인공지능의 저작권, 윤리문제 등에 대해 더 자세히 알 수 있는 유익한 시간이었습니다. 또한 독서모임 후 뒷풀이를 통해 회원 간에 관계를 돈독하게 할 수 있는 시간도 마련 되었습니다. 차기 제7회 독서모임은 2024.10.31 (목) 19시~21시 에 같은 장소인 역삼동 대명빌딩 401호에서 진행되오니 관심있는 포럼 회원분들의 많은 참여 부탁드립니다.','2024-09-05','','','',1,91,'2024-09-05 00:00:00','2024-09-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[답사보고] 포럼 중국 백두산 두만강 및 북중러 접경지역 답사 행사 성료','안녕하십니까 , 어느덧 가을로 접어드는 9 월이 시작되었습니다 . 지난 8 월 27 일 부터 31 일까지 4 박 5 일간 석호익 회장님을 비롯한 포럼회원 23 명이 중국 백두산 두만강 및 북중러 접경지역을 회원 여러','안녕하십니까 , 어느덧 가을로 접어드는 9 월이 시작되었습니다 . 지난 8 월 27 일 부터 31 일까지 4 박 5 일간 석호익 회장님을 비롯한 포럼회원 23 명이 중국 백두산 두만강 및 북중러 접경지역을 회원 여러분들의 성원에 힘입어 무사히 잘 다녀왔음을 보고드립니다 . 중국 연길시 개발부 IT 밸리도 방문하여 네이버 , 쿠팡 등 우리나라 입주 업체 현황도 견학했습니다 . 내년 여름에도 갈 계획이오니 관심있는 분들은 그 때 많이 신청해 주시기 바랍니다 . 주요 단체사진 몇 장을 올려드립니다 .','2024-09-02','','','',1,90,'2024-09-02 00:00:00','2024-09-02 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[모집안내] 제6기 통일 ICT 전문가 교육 수강생 모집','다음과 같이 통일 ICT 전문가 교육 6기 수강생을 모집하오니 관심있는 분들의 많은 신청과 주위 분들에게 소개를 부탁드립니다. 수강신청서는 1. 하기 구글폼 링크에 접속하셔서 작성해 주시거나 2. 첨부된 수강신청서를','다음과 같이 통일 ICT 전문가 교육 6기 수강생을 모집하오니 관심있는 분들의 많은 신청과 주위 분들에게 소개를 부탁드립니다. 수강신청서는 1. 하기 구글폼 링크에 접속하셔서 작성해 주시거나 2. 첨부된 수강신청서를 작성해 주셔서 bismak0308@naver.com 으로 보내주시고, 3. 지정된 계좌로 수강료를 입금해 주시면 됩니다. <수강신청 - 구글폼 링크> https://docs.google.com/forms/d/e/1FAIpQLSfk4EoquNzaqtvJ2XfdXDsMn7xI_r7vXO-gz__PkgepLKSb4Q/viewform?usp=sf_link','2024-08-26','','통일 ict 전문가 교육 수강신청서(제6기)2024.hwp [43KB]','',1,89,'2024-08-26 00:00:00','2024-08-26 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','백두산⦁두만강⦁연변 지역 답사 참가자 모집','백두산 ⦁ 두만강 ⦁ 연변 지역 답사 참가자 모집 안녕하십니까 ? 백두산 . 두만강 . 북중러 접경지역 답사를 통하여 최근 변화된 주변정세를 파악하고 , 회원간 정보교류를 위하여 별첨과 같이 답사 희망자를 선착순 3','백두산 ⦁ 두만강 ⦁ 연변 지역 답사 참가자 모집 안녕하십니까 ? 백두산 . 두만강 . 북중러 접경지역 답사를 통하여 최근 변화된 주변정세를 파악하고 , 회원간 정보교류를 위하여 별첨과 같이 답사 희망자를 선착순 30 분을 모집하오니 희망하시는 분은 4.23 일까지 예약금 20 만원을 입금하여 주시기 바랍니다 . < 개요 > 1. 답사일시 : 2024.8.27( 화 ) ~ 8.31( 토 ) ※ 상세일정 참조 2. 답사장소 : 백두산 , 두만강 , 룡정 , 훈춘 , 룡호각 , 북 · 중 · 러 국경 지대 3. 참가비용 : 1 인당 120 만원 ( 단체비자 발급비 1 인당 6 만원 포함 ) - 개별비자 발급자는 1 인당 114 만원 - 2 인 1 실 원칙 ( 객실 1 인 사용 희망자 : 22 만원 추가납부 ) 4. 항공료 예약을 위한 Deposit 을 속히 해야 하는 관계로 답사 참가희망자는 4.23( 화 ) 까지 아래 계좌로 예약금 20 만원을 입금 바랍니다 . ※ 하나은행 / 103-910045-72904 / 사단법인동북아공동체 ICT 포럼 5. 기 타 자세한 사항은 추가 안내 드릴 계획이며 , 궁금한 사항은 문의 바랍니다 . ( 연락처 : 010-2378-2060 / 동북아공동체 ICT 포럼 구교광 부회장 )','2024-04-18','','백두산 답사 안내.pdf [281KB]','',1,88,'2024-04-18 00:00:00','2024-04-18 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제3기 [초거대AI활용 생성테크] 교육 안내','■ 구글폼 신청 링크 : https://forms.gle/2oueJimnawPNoT417 ■ 수강신청서 하단 첨부파일 참조 ■ 교육참가 안내','■ 구글폼 신청 링크 : https://forms.gle/2oueJimnawPNoT417 ■ 수강신청서 하단 첨부파일 참조 ■ 교육참가 안내','2024-03-27','','제3기 초거대ai 교육_수강신청서.hwp [41KB]','',1,87,'2024-03-27 00:00:00','2024-03-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제86회 조찬간담회 참석 요청','그간 안녕하십니까 ? 한국전자통신연구원 (ETRI) 방승찬 원장님을 연사로 초청하여 동북아공동체 ICT 포럼 제 86 차 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다 . ▶ 일','그간 안녕하십니까 ? 한국전자통신연구원 (ETRI) 방승찬 원장님을 연사로 초청하여 동북아공동체 ICT 포럼 제 86 차 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다 . ▶ 일 시 : 2024 년 4 월 19 일 ( 금 ) - 07:00 ~ 07:30 접수 및 등록 - 07:30 ~ 09:00 조찬 및 발표 - 09:00 ~ 09:05 단체 기념사진 촬영 ▶ 장 소 : 삼정호텔 본관 2 층 라벤더홀 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 6 만원 / [ 개인회원 30 만원 이상 , 기관회원 100 만원 , 기업회원 200 만원 이상 년회비 납부하신 분은 무료 ] - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제 : 첨단 로봇 · 제조 전략기술과 AI 디지털 혁신 ▶ 연 사 : 방승찬 한국전자통신연구원장 ( 학 력 ) - 1980.3 ~ 1984.2 서울대학교 전자공학 학사 - 1984.3 ~ 1986.2 서울대학교 전자공학 석사 - 1989.3 ~ 1994.8 서울대학교 전자공학 박사 ( 주요경력 ) - 2022.12~ 현재 한국전자통신연구원 원장 - 2021.01~ 현재 한국공학한림원 일반회원 , 자율주행위원회 위원 - 2023.04~ 현재 소재 · 부품 · 장비 경쟁력강화위원회 민간위원 - 한국통신학회 / 한국전자파학회 부회장 역임 , 위성통신포럼 /5G 포럼 공동의장 역임 ( 수상내역 ) - 2021.12., 해동기술대상 , 한국통신학회 , 해동과학문화재단 - 2014.12., 한국공학상 , 대통령 , 한국연구재단 - 2006.06., 국무총리표창 - 1998.12., 정보통신부장관표창 ▶ 참가신청 방법 : 이메일이나 문자 회신 , 포럼 단체 카톡방이나 전화 신청 ( 소속 . 직위 . 핸드폰 번호 ) ▶ 문의처 : 010-2378-2060 ( 구교광 부회장 / bismak0308@naver.com) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림','2024-03-14','','','',1,86,'2024-03-14 00:00:00','2024-03-14 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2023년 연간기부금 모금액 활용실적 명세서 보고','<2023 년도 기부금 모금액 및 활용실적 보고 > 기부금 모금 기간 : 2023. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2023. 01. 01. ~ 12. 31. [ 보고 근거 ] - 우리 포럼은 ','<2023 년도 기부금 모금액 및 활용실적 보고 > 기부금 모금 기간 : 2023. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2023. 01. 01. ~ 12. 31. [ 보고 근거 ] - 우리 포럼은 기획재정부장관이 지정한 지정기부금단체입니다 . - 또한 사단법인 동북아공동체 ICT 포럼 정관 제 21 조 제 2 항 ( 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음연도 3 월말까지 공개한다 ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . [ 기부금 수입 ] * 수입총액 : 19,200,000 원 a. 개인 기부금 : 2,000,000 원 b. 단체 기부금 : 17,200,000 원 [ 기부금 지출 ] * 지출총액 : 19,200,000 원 a. 조찬간담회 행사비용 외 : 19,200,000','2024-03-11','','2023_연간기부금 모금액 및 활용실적 명세서.pdf [123KB]','',1,85,'2024-03-11 00:00:00','2024-03-11 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','후원하기','민간차원의 남북 IT 교류 협력방안 제시와 정보화를 통한 남북 경협에의 기여를 위해 귀하의 후원을 부탁드립니다 . 무통장입금정보 - 은행명 : 하나은행 / 계좌번호 : 103-910044-13304 - 예금주 : (','민간차원의 남북 IT 교류 협력방안 제시와 정보화를 통한 남북 경협에의 기여를 위해 귀하의 후원을 부탁드립니다 . 무통장입금정보 - 은행명 : 하나은행 / 계좌번호 : 103-910044-13304 - 예금주 : ( 사 ) 동북아공동체 ICT 포럼 우리 포럼은 기획재정부에 지정기부금 단체로 등록되어 있어 , 후원금 및 기부금을 내시면 법인세법 제 24 조의 규정에 의하여 - 개인은 연말소득공제를 받을 수 있고 - 법인은 손비처리가 가능합니다 . 기부금 영수증 신청 - 개인 : 성명 / 주민등록번호 / 핸드폰번호 / 주소 - 기업 : 법인사업자등록증 사본 2014 년 8 월부터 「 개인정보보호법 」 개정법 시행으로 주민등록번호 수집 이용이 금지됐으나 , 기부금영수증 발급을 위한 주민등록번호 수집과 이용은 허용하고 있습니다 .( 사 ) 동북아공동체 ICT 포럼은 후원자님의 소중한 개인정보를 기부금영수증 발급용으로만 수집 · 이용하며 안전하게 관리하겠습니다 . - 문의 : 사무국 02) 521-8171','2023-11-09','','','',1,84,'2023-11-09 00:00:00','2023-11-09 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','11월 4일 (토) 남한산성 산행 참가요청','■ 장 소: 남한산성 (南漢山城) ■ 일 시: 2023년 11월 04일(토) 10:00 ~ 13:00 ■ 집 결: 남한산성 종점 주차장 10:00 까지 도착 -교통편: 8호선 산성역 2번출구 약 100미터 앞 포레스','■ 장 소: 남한산성 (南漢山城) ■ 일 시: 2023년 11월 04일(토) 10:00 ~ 13:00 ■ 집 결: 남한산성 종점 주차장 10:00 까지 도착 -교통편: 8호선 산성역 2번출구 약 100미터 앞 포레스티아 동문 버스주차장 9-1, 52번 버스.종점까지 약 20분 소요 -자동차 종일 주차비 5,000원 ■ 코 스 - 남문 주차장 → 산성종로(로타리) → 북문(전승문) → 서문(우익문) → 수어장대 → 영춘정 → 남문(지화문) → 산성종로(로타리) ※ 남한산성 행궁 투어 ■ 참가비: 10,000원 (기타 협찬이나 후원 가능합니다) ■ 점 심: 추후 통보 예정 [ 행사안내 및 협찬문의 ] ■ 총 괄: 황순연 산악회장(☎ 010-9043-8287) ■ 진 행: 김순호 사무부총장(☎ 010-4525-5251) ■ 지 원: 구교광 포럼 부회장(☎ 010-2378-2060) 회원님들의 건강과 만사형통을 기원드립니다. 감사합니다. 동북아ICT포럼 원우회 회장 전진우 배상','2023-10-19','','','',1,83,'2023-10-19 00:00:00','2023-10-19 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제2기 "초거대AI활용 생성테크" 교육 입학식 및 강의 개시','회원 여러분의 지원 덕분에 "제2기 초거대AI활용 생성테크" 교육이 9월 19일 19시 피스센터(강동구 성내동 소재) 2층 대강당에서 입학식 후 매주 화요일 10회의 강의가 시작되었습니다. 바쁘신 중에서도 교육생을 ','회원 여러분의 지원 덕분에 "제2기 초거대AI활용 생성테크" 교육이 9월 19일 19시 피스센터(강동구 성내동 소재) 2층 대강당에서 입학식 후 매주 화요일 10회의 강의가 시작되었습니다. 바쁘신 중에서도 교육생을 참여시켜 주신 회원님들께 감사 드리며, 아무쪼록 이번 교육과 체험을 통해 획기적인 업무생산성을 개선하고 AI산업 발전에 도움되시기를 바랍니다.','2023-09-21','','','',1,82,'2023-09-21 00:00:00','2023-09-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제2기 초거대AI 생성테크 교육 참가 안내','제2기 초거대AI 생성테크 교육 참가 안내','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2023-08-24','','제2기 초거대ai 교육.pdf [414KB]','',1,81,'2023-08-24 00:00:00','2023-08-24 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 83회 조찬간담회 참석 요청','그간 안녕하십니까 ? 우동기 지방시대위원장님을 연사로 초청하여 동북아공동체 ICT 포럼 제 83 회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청을 바랍니다 . ▶ 일 시 : 2023 년','그간 안녕하십니까 ? 우동기 지방시대위원장님을 연사로 초청하여 동북아공동체 ICT 포럼 제 83 회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청을 바랍니다 . ▶ 일 시 : 2023 년 9 월 5 일 ( 화 ) - 07:00 ~ 07:30 접수 및 등록 - 07:30 ~ 09:00 조찬 및 발표 - 09:00 ~ 09:05 단체 기념사진 촬영 ▶ 장 소 : 삼정호텔 본관 2 층 라벤더 홀 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 5 만원 / [ 개인회원 25 만원 이상 , 기관회원 100 만원 , 기업회원 200 만원 이상 년회비 납부하신 분은 무료 ] - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제 : 이제는 지방시대, 다시 뛰는 대한민국! 그 비전과 전략 ▶ 연 사 : 우동기 지방시대위원회 위원장 ( 학 력 ) - 쓰쿠바 대학교 대학원 사회공학 박사 - 볼 주립대학교 인문학 명예 박사 - 대구 카톨릭대학교 대학원 신학 석사 ( 주요경력 ) - 영남대학교 총장 - 제 8,9 대 대구 교육청 교육감 - 대구 카톨릭 대학교 총장 - 제 20 대 대통령취임준비위원회 부위원장 - 국가균형발전위원회 위원장 ( 수상내역 ) - 한국의 존경받는 CEO 대상 ▶ 참가신청 방법 : 이메일이나 문자 회신 , 포럼 단체 카톡방이나 전화 신청 ( 소속 . 직위 . 핸드폰 번호 ) ▶ 문의처 : 010-2378-2060 ( 구교광 부회장 / bismak0308@naver.com) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림','2023-08-21','','','',1,80,'2023-08-21 00:00:00','2023-08-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2022년도 기부금 모금액 활용실적 명세서','<2022 년도 기부금 모금액 및 활용실적 보고 > 기부금 모금 기간 : 2022. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2022. 01. 01. ~ 12. 31. [ 보고 근거 ] - 우리 포럼은 ','<2022 년도 기부금 모금액 및 활용실적 보고 > 기부금 모금 기간 : 2022. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2022. 01. 01. ~ 12. 31. [ 보고 근거 ] - 우리 포럼은 기획재정부장관이 지정한 지정기부금단체입니다 . - 또한 사단법인 동북아공동체 ICT 포럼 정관 제 21 조 제 2 항 ( 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음연도 3 월말까지 공개한다 ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . [ 기부금 수입 ] * 수입총액 : 12,600,000 원 a. 개인 기부금 : 2,350,000 원 b. 단체 기부금 : 10,250,000 원 [ 기부금 지출 ] * 지출총액 : 12,600,000 원 a. 조찬간담회 : 12,600,000 원','2023-04-10','','2022_공개 보고서 기부금모금액 및 활용실적명세.pdf [61KB]','',1,79,'2023-04-10 00:00:00','2023-04-10 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2023년 초거대AI 활용 생성테크 교육','1. 챗 GPT 가 쏘아올린 '' 생성 AI'' 개발 경쟁이 갈수록 격화하고 있디 . 챗 GPT 를 개발한 오픈 AI 와 손을 맞잡은 마이크로소프트 (MS) 가 기선을 잡은 가운데 구글도 생성 AI 사트트업 앤트로픽과 ','1. 챗 GPT 가 쏘아올린 '' 생성 AI'' 개발 경쟁이 갈수록 격화하고 있디 . 챗 GPT 를 개발한 오픈 AI 와 손을 맞잡은 마이크로소프트 (MS) 가 기선을 잡은 가운데 구글도 생성 AI 사트트업 앤트로픽과 동맹을 맺는 등 대결구도를 형성했다 여기에 아마존과 메타 , 일론 머스크도 경쟁에 뛰어들면서 5 파전 양상을 형성했다 . 2. 우리 정부에서도 초거대 인공지능 (AI) 주도권 확보를 위해 기술 , 산업인프 라 구축 , 산업혁신 생태계 조성을 위한 ‘ 초거대 AI 경쟁력 강화방안 ’ 을 발표하고 올해 3,901 억원을 투입한다고 밝혔다 . 3. 이에 우리 포럼에서는 획기적인 업무생산성 개선과 창업을 위한 체험 중 심 교육을 준비했다 . 4. 교육특징 ① 여덟번의 이론 강의와 네 번의 체험 강의 병행 ② MS, 네이버, 카카오 및 KT, SKT, LG유플러스 등 국내외 최대 전문기관 강사 확보 ③ 상대적으로 저렴한 수강료 ( 모 신문사의 유사 교육 수강료는 160 만원 임 ) ④ 저녁 식사 제공 ( 교육비에 12 번의 식사비 12 만원 포함됨 ) 5. 할인혜택 : 포럼회원 10%, 통일 ICT 전문가 원우 10%, 최대20% 할인','2023-03-29','','챗-gpt 수강신청서 2023.hwp [40KB]','',1,78,'2023-03-29 00:00:00','2023-03-29 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2022년 제5기 통일ICT전문가 아카데미 신청안내','2022년 제5기 통일ICT전문가 아카데미 신청안내','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2022-07-27','','수강신청서 2022.07.hwp [14KB]','',1,77,'2022-07-27 00:00:00','2022-07-27 00:00:00');
