INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','북한의 IT기술 현황과 남북 협력 방안 유튜브 시청 요청','안녕하십니까? 우리 포럼에서 (재)통일과 나눔으로부터 과제를 지원 받아 북한의 4차산업혁명, 휴대전화 사용실태, 전자결제, 북한의 사이버 보안 등에 대한 전문가의 발표 및 토론 동영상을 준비했습니다. 꼭 한번 들어보','안녕하십니까? 우리 포럼에서 (재)통일과 나눔으로부터 과제를 지원 받아 북한의 4차산업혁명, 휴대전화 사용실태, 전자결제, 북한의 사이버 보안 등에 대한 전문가의 발표 및 토론 동영상을 준비했습니다. 꼭 한번 들어보시고 2.10(목) 오후 4시부터 6시까지 유튜브로 실시간 개최되는 질의응답 시간에 많은 질문과 의견 제시를 부탁드립니다. 2.10일 전에 질문과 의견을 제게 주셔도 됩니다. 구교광 올림(010-2378-2060, bismak0308@naver.com) 여기 유튜브 링크를 통해 보실 수 있습니다. https://www.youtube.com/watch?v=LvfPs900SHM&list=PLhrgD__CWBP97QDmvprkj3hCGgofKOrPU','2022-02-03','','','',1,75,'2022-02-03 00:00:00','2022-02-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2016년도 기부금 모금액 및 활용실적','2016 년도 기부금 모금액 및 활용실적 기부금 모금 기간 : 2016.7.1.~12.31 기부금 활용 기간 : 2016.7.1.~12.31 사단법인 동북아공동체ICT포럼은 정관 제 21 조 제2 항 (법인은 법인 ','2016 년도 기부금 모금액 및 활용실적 기부금 모금 기간 : 2016.7.1.~12.31 기부금 활용 기간 : 2016.7.1.~12.31 사단법인 동북아공동체ICT포럼은 정관 제 21 조 제2 항 (법인은 법인 및 국세청의 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음 연도 3월31일까지 공개한다. ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . ﻿ 【 기부금 수입 】 ● 수입총액 : 0원 【 기부금 지출 】 ● 지출총액 : 0 원 ※ 자세한 내용은 국세청홈페이지에서도 확인하실 수 있습니다 .','2022-01-27','','연간 기부금 모금액 및 활용실적 명세서_2016 (17.03.15).hwp [48KB]','',1,74,'2022-01-27 00:00:00','2022-01-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','"ICT를 활용한 남북한 원격교류 협력방안"학술행사 영상 링크','동북아공동체ICT포럼에서 11월 24일날 주관한 학술행사 "ICT를 활용한 남북한 원격교류 협력방안"을 성황리에 마쳤습니다. 유튜브 채널을 개설하여 전체 행사영상을 유튜브에 올렸으니 많은 관심바랍니다. <ICT를 활','동북아공동체ICT포럼에서 11월 24일날 주관한 학술행사 "ICT를 활용한 남북한 원격교류 협력방안"을 성황리에 마쳤습니다. 유튜브 채널을 개설하여 전체 행사영상을 유튜브에 올렸으니 많은 관심바랍니다. <ICT를 활용한 남북한 원격교류 협력방안> https://youtu.be/Jbd4b7Eop9E 실시간 생중계영상 유튜브 링크입니다. 행사순서는 다음과 같습니다. 개회사 (~5:00) 이상민 국회의원 환영사 (5:00~10:00) 석호익 회장 축사(10:00~13:00) 양정숙 의원 기조연설 (15:00~48:00) 4차 산업혁명시대 북한의 ICT발전 전략과 강성대국 남성욱 교수(고려대) 발제 (48:00~1:20:00) 북한의 ICT 현황과 전망 김흥광 교수(前 북한 공산대 컴퓨터학과 교수) 발제 (1:20:00~1:45:00) 남북한 전자정부 협력방안 신영진 교수(배재대) 발제 (1:55:00~2:23:00) 원격 교육을 활용한 남북한 협력 방안 최성 연구소장(동북아공동체ICT포럼) 발제 (2:23:00~2:48:00) 화상회의를 통한 남북한 협력방안 이정진 팀장(KT) 발제 ( 2:48:00~3:15:00) 팬데믹 하에서의 남북한 원격진료 활용방안 김영훈 교수(고려대)','2021-12-01','','','',1,73,'2021-12-01 00:00:00','2021-12-01 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','11.24(수) 학술행사 실시간 생중계 [''ICT를 활용한 남북한 원격교류 협력방안'']','''ICT를 활용한 남북한 원격교류 협력방안'' 학술행사 (유튜브 실시간 생중계를 많은 시청 부탁드립니다.) 북한의 4차산업혁명 등 최근 ICT현황을 알아보고, 남북한 원격진료, 원격교육, 화상 회의 및 전자정부 협력방','''ICT를 활용한 남북한 원격교류 협력방안'' 학술행사 (유튜브 실시간 생중계를 많은 시청 부탁드립니다.) 북한의 4차산업혁명 등 최근 ICT현황을 알아보고, 남북한 원격진료, 원격교육, 화상 회의 및 전자정부 협력방안에 대해 전문가의 발표와 토론을 들을 수 있는 귀한 기회이오니 많은 시청 바랍니다. 일시: 2021.11.24수 13:30~18:00 아래에 있는 유튜브 실시간 생중계 링크를 클릭 하시거나, 유튜브 검색창에서 ''동북아공동체ICT''을 검색해서 시청할 수 있습니다. (생중계 방송 중에 질문이나 코멘트를 보내시려면 유튜브에서 접속해야 합니다.) https://youtu.be/Jbd4b7Eop9E','2021-11-23','','2021 통일부 학술행사.jpeg [8071KB]','',1,72,'2021-11-23 00:00:00','2021-11-23 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','11.24 (수) "ICT를 활용한 남북한 원격교류 활용방안"학술행사 참가자 선착순 모집','(11.24수 13:30 "ICT를 활용한 남북한 원격교류 활용방안"학술행사 참가자 선착순 모집) 1. 일시:11.24(수)13:30~18:00 2.장소: 국회의원회관2층 제1소회의실 3.모집인원:40명(코로나 방역','(11.24수 13:30 "ICT를 활용한 남북한 원격교류 활용방안"학술행사 참가자 선착순 모집) 1. 일시:11.24(수)13:30~18:00 2.장소: 국회의원회관2층 제1소회의실 3.모집인원:40명(코로나 방역관계로 참가자수 제한),참가자에게는 석식 제공 (개최 배경) 북한핵 문제로 인한 대북재제와 코로나19후유증으로 앞으로도 상당기간 직접적인 남북 접촉의 어려움이 예상되고,남북교류 가능 시기에도 남북접촉을 효율적으로 하기 위하여 ICT를 활용한 남북한 원격교류 활용 방안 연구가 필요한 때입니다. 이에 관계 전문가를 모시고 김정은 시대의 북한의 ICT현황 등을 알아보고, 남북한 전자정부,원격교육,화상회의,원격진료에 대한 발표와 토론의 장을 가지고자 하오니 많은 신청바랍니다. 자세한 사항은 포스터 참조 바랍니다. 동북아공동체ICT 회장 석호익 배상 연락처: 구교광 부회장(010-2378-2060)','2021-11-16','','2021 통일부 학술행사.jpeg [8071KB]','',1,71,'2021-11-16 00:00:00','2021-11-16 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','11월5일(금) 동북아공동체ICT포럼 제74회 조찬간담회 참석 요청','그간 안녕하십니까 ? 통신 3 사의 메타버스 담당 임원을 초청하여 동북아공동체 ICT 포럼 제 74 회 조찬 간담회를 아래와 같이 개최하고자 합니다 . 젊은 사람들의 일시적인 호기심을 넘어서 전사업적으로 확대될 것이','그간 안녕하십니까 ? 통신 3 사의 메타버스 담당 임원을 초청하여 동북아공동체 ICT 포럼 제 74 회 조찬 간담회를 아래와 같이 개최하고자 합니다 . 젊은 사람들의 일시적인 호기심을 넘어서 전사업적으로 확대될 것이 주목되는 메타버스의 추진현황과 향후 계획에 대해 알아볼 수 있는 좋은 기회이니 회원 여러분들의 많은 참가신청 바랍니다 . ▶ 일 시 : 2021 년 11 월 05 일 ( 금 ) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 07:50 조찬 및 인사 08:00 ~ 09:00 발표 및 질의 ▶ 장 소 : 한국프레스센터 19 층 매화홀 (Tel. 02-2001-7114) - 서울시 중구 세종대로 124 번지 - 지하철 1,2 호선 시청역 4 번 출구 53 미터 , 5 호선 광화문역 시청방향 - 주차 무료 ( 참가 시 차량번호 사전 등록 필수 ) ▶ 참가비 : 5 만원 / 개인 회원 25 만원 이상 ( 기관회원 100 만원 , 기업회원 200 만원이상 ) 년회비 납부하신 분은 무료 - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제 : 통신 3 사의 메타버스 추진 현황과 계획 ▶ 연 사 : - KT: 배순민 연구소장 -SKT: 성석함 상무 - LG 유플러스 : 김민구 상무 ▶ 참가신청 방법 : 메일 회신 , 포럼 단체 카톡방이나 전화 신청 ( 소속 . 직위 . 핸드폰 번호 ) ▶ 코로나 사태로 오프라인 행시가 어려울 경우에는 Zoom 을 이용한 온라인 행사 예정 , 별도 안내 ▶ 행사 시에 코로나 19 예방을 위해 발열체크 , 소독약 비치 , 좌석 띄어앉기 등 최선을 기하겠습니다 . ▶ 문의처 : 010-2378-2060( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림','2021-10-21','','','',1,70,'2021-10-21 00:00:00','2021-10-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','7월9일(금) 동북아공동체ICT포럼 제73회 조찬간담회 참석 요청','그간 안녕하십니까? 한국인터넷진흥원 이원태 원장님을 초청하여 동북아공동체ICT포럼 제73회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다. ▶ 일 시: 2021년 7월 09일(금','그간 안녕하십니까? 한국인터넷진흥원 이원태 원장님을 초청하여 동북아공동체ICT포럼 제73회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다. ▶ 일 시: 2021년 7월 09일(금) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 09:00 ~ 09:05 단체사진 촬영 ▶ 장 소: 삼정호텔 신관 2층 젤라늄 홀 대연회장(Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9호선 언주역 8번 출구 도보 3분 거리 | 주차 무료 ▶ 참가비: 5만원 / 개인 회원 25만원 이상(기관회원 100만원 ,기업회원 200만원이상) 년회비 납부하신 분은 무료 - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제: 코로나19 이후 언택트 시대 사이버 보안 위협 의 양상과 대응방향 ▶ 연 사: 이원태 원장 (주요 경력) - 서강대학교 사회과학연구소 상임 연구원 -정보통신정책연구원 미래융합연구실 연구위원 - 한국인터넷자율정책기구 저널 편집위원 - 정보통신정책연구원 ICT전략연구실 연구책임자 - 제6대 한국인터넷진흥원 원장 ▶ 참가신청 방법:문자 회신,포럼 단체 카톡방이나 전화 신청 (소속.직위. 핸드폰 번호) ▶문의처: 010-2378-2060 (구 교광 부회장) (사)동북아공동체ICT포럼 석호익 회장 올림','2021-06-23','','','',1,69,'2021-06-23 00:00:00','2021-06-23 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','동북아공동체ICT포럼 제72회 조찬간담회 참석 요청','그간 안녕하십니까? 제3대 평양과기대 이승률 총장님을 초청하여 동북아공동체ICT포럼 제72회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다. ▶ 일 시: 2021년 5월 4일(화','그간 안녕하십니까? 제3대 평양과기대 이승률 총장님을 초청하여 동북아공동체ICT포럼 제72회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다. ▶ 일 시: 2021년 5월 4일(화) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 09:00 ~ 09:05 단체사진 촬영 ▶ 장 소: 삼정호텔 신관 1층 Adonis 대연회장(Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9호선 언주역 8번 출구 도보 3분 거리 | 주차 무료 ▶ 참가비: 5만원 / 개인 회원 25만원 이상(기관회원 100만원 ,기업회원 200만원이상) 연회비 납부하신 분은 무료 - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제: 동북아 자연경제권과 한반도의 미래 ▶ 연 사: 이승률 제3대 평양과기대 총장 <학력> - 동국대학교 대학원 철학과 석사 - (중국)연변대학 대학원 국제정치학 석사 - (중국)중앙민족대학교 사회학학원 법학박사 <경력> - 평양과학기술대학 공동운영총장(2021 ~ 현재) - 평양과학기술대학 대외부총장(2012 ~ 2017) - (사)동북아공동체문화재단 이사장(2007 ~ 현재) - (주)반도이앤씨 회장(1986 ~ 현재) <수상 경력> - 대한민국 국민훈장 목련장(216.11.12) - 2016년 환황해경제·기술교류대상(2016.7.13.) <저서> - 「회복의 능력」 (2021, 올리브나무) - 「린치핀코리아」 (2020, 동북아공동체문화재단) - 「북방에서 길을 찾다」 (공저, 2017, 디딤터) - 「동아시아 영토분쟁과 국제협력」 (공저, 2014, 디딤터) ▶ 참가신청 방법:문자 회신,포럼 단체 카톡방이나 전화 신청 (소속.직위. 핸드폰 번호) ▶코로나 사태로 오프라인 행시가 어려울 경우에는 Zoom을 이용한 온라인 행사 예정,별도 안내 ▶문의처: 010-2378-2060(구 교광 부회장) (사)동북아공동체ICT포럼 석호익 회장 올림','2021-04-15','','','',1,68,'2021-04-15 00:00:00','2021-04-15 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2020년도 기부금 모금액 및 활용실적 보고','2020 년도 기부금 모금액 및 활용실적 보고 기부금 모금 기간 : 2020. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2020. 01. 01. ~ 12. 31. [보고 근거] - 우리 포럼은 기획재정부','2020 년도 기부금 모금액 및 활용실적 보고 기부금 모금 기간 : 2020. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2020. 01. 01. ~ 12. 31. [보고 근거] - 우리 포럼은 기획재정부장관이 지정한 지정기부금단체입니다. - 또한 사단법인 동북아공동체 ICT 포럼 정관 제 21 조 제 2 항 ( 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음연도 3 월말까지 공개한다 ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . [ 기부금 수입 ] * 수입총액 : 15,400,000 원 a. 개인 기부금 : 2,400,000 원 b. 단체 기부금 : 13,000,000 원 [ 기부금 지출 ] * 지출총액 : 15,400,000 원 a . 조찬간담회 : 6,438,000 원 b. 사무실 관리비 : 4,066,040 원 c. 인건비 보조 : 4,895,960 원','2021-03-25','','\[고시용] 연간 기부금 모금액 및 활용실적 명세서_2020 (21.03.25).pdf.pdf [622KB]','',1,67,'2021-03-25 00:00:00','2021-03-25 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','동북아공동체ICT포럼 제71회 조찬간담회겸 포럼 정기총회 참석 요청','그간 안녕하십니까? 통일부 서 호 차관님을 초청하여 동북아공동체ICT포럼 제71회 조찬 간담회겸 포럼 정기총회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다. ▶ 일 시: 2021년 2월 2','그간 안녕하십니까? 통일부 서 호 차관님을 초청하여 동북아공동체ICT포럼 제71회 조찬 간담회겸 포럼 정기총회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참가신청 바랍니다. ▶ 일 시: 2021년 2월 24일(수) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 09:00 ~ 09:20 정기총회 ▶ 장 소: 삼정호텔 신관 1층 Adonis 대연회장(Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9호선 언주역 8번 출구 도보 3분 거리 | 주차 무료 ▶ 참가비: 5만원 / 개인 회원 25만원 이상(기관회원 100만원 ,기업회원 200만원이상) 년회비 납부하신 분은 무료 - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제: 한반도 정세와 남북 관계 추진 방안 ▶ 연 사: 서 호 통일부 차관 - 1991.8 고려대 정책과학 대학원 석사 - 2010.6 통일부 교류협력국장 - 2013.7 통일부 남북출입국사무소 소장 - 2018.9~2019.5 국가안보실 통일정책비서관 - 2019.5~현재 통일부 차관 ▶ 참가신청 방법: 이메일에 답신, 전화 또는 포럼단체 카톡방으로 신청(소속, 직위 ,핸드폰 번호) ▶코로나 사태로 대면 행사가 어려울 경우에는 Zoom을 이용한 비대면 행사 예정,별도 안내 ▶문의처: 010-2378-2060(구 교광 부회장) (사)동북아공동체ICT포럼 석호익 회장 올림','2021-02-09','','','',1,66,'2021-02-09 00:00:00','2021-02-09 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제70회 조찬 간담회 겸 임시총회 개최 안내','그간 안녕하십니까 ? 권호열 정보통신정책연구원 (KISDI) 원장님을 초청하여 동북아공동체 ICT 포럼 제 70 회 조찬 간담회 겸 포럼 임시총회를 아래와 같이 개최하고자 하오니 , 회원 여러 분들의 많은 참가를 바','그간 안녕하십니까 ? 권호열 정보통신정책연구원 (KISDI) 원장님을 초청하여 동북아공동체 ICT 포럼 제 70 회 조찬 간담회 겸 포럼 임시총회를 아래와 같이 개최하고자 하오니 , 회원 여러 분들의 많은 참가를 바랍니다 . ▶ 일 시 :11 월 17 일 (화 요일 ) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 09:00 ~ 09:20 포럼 임시총회 ▶ 장 소 : 삼정호텔 신관 1 층 Adonis 대연회장 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 발표 주제 : 한국판 뉴딜과 디지털 대전환 ▶ 참가비 : 4 만원 / 개인 회원 20 만원 이상 ( 기관회원 100 만원 이상 ) 년회비 납부하신 분 : 무료 - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 합니다 . ▶ 참가 신청 : 참가하실 분은 반드시 사전에 참가신청 바랍니다 : 포럼 단체 카톡방 , 문자 회신 , 전화로 신청 ▶ 코로나 19 방역을 위해 열화상감지기 설치 , 손소독제 비치 , 좌석 띄어 앉기 , 마스크 착용등 만전을 기하겠습니다 . ▶ 문의처 : 010-2378-2060 ( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림','2020-10-20','','','',1,65,'2020-10-20 00:00:00','2020-10-20 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','포럼 창립 20주년 기념 ICT 남북교류 좌담회','본 포럼 창립 20 주년 (9 월 21 일 ) 를 맞이하여 전자신문과 "ICT 남북교류 좌담회 " 를 가졌습니다 . 일시 및 장소 : 2020.9.17. 전자신문사 회의실 참석자 : 김광길 ( 통일부 교류 협력정책관','본 포럼 창립 20 주년 (9 월 21 일 ) 를 맞이하여 전자신문과 "ICT 남북교류 좌담회 " 를 가졌습니다 . 일시 및 장소 : 2020.9.17. 전자신문사 회의실 참석자 : 김광길 ( 통일부 교류 협력정책관 ), 석호익 ( 동북아공동체 ICT 포럼 회장 ), 유창근 ( 개성공단기업협회 부회장 , 본 포럼 이사 ), 윤영찬 ( 더불어민주당 의원 ), 이상산 ( 한동대학교 교수 , 본 포럼 이사 ), 최성 ( 동북아공동체 ICT 포럼 연구소장 ) ※ 자세한 사항은 https://www.etnews.com/20200922000214 https://www.etnews.com/20200921000219 참고하여 주시기를 바라오며 , 그 동안 포럼 창립과 발전을 위하여 참여해주신 모든 분들과 관계 기관에 깊은 감사의 말씀을 드립니다 . 앞으로도 남북교류협력 활성화를 위한 포럼 활동에 많은 참여와 지원을 부탁드리오며 , 포럼 신규 사업 추진과 내실화를 위하여 후원금이 필요하오니 뜻있는 분들에 많은 협조를 부탁드립니다 . 후원계좌 : 하나은행 103-910044-13304( 예금주 : 동북아공동체 ICT 포럼 ) 본 포럼은 기획재정부로부터 지정기부금 단체로 지정받아 , 기부금을 내실 경우 기업은 손비처리가 가능하고 개인은 연말정산시 혜택을 받을 수 있습니다 . ( 문의 사항 : 010-2378-2060 구교광 부회장 ) 2020.9.23 동북아공동체 ICT 회장 석호익','2020-09-23','','','',1,64,'2020-09-23 00:00:00','2020-09-23 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 69회 조찬간담회 개최 안내','회원 여러분 안녕하십니까 ? 본 포럼에서는 국회 ICT 융합포럼 공동 대표이신 조명희 의원님을 초청하여 제 69 회 조찬간담회를 아래와 같이 개최하고자 하오니 , 관심 있는 분들의 많은 참가를 바랍니다 . - 아 래','회원 여러분 안녕하십니까 ? 본 포럼에서는 국회 ICT 융합포럼 공동 대표이신 조명희 의원님을 초청하여 제 69 회 조찬간담회를 아래와 같이 개최하고자 하오니 , 관심 있는 분들의 많은 참가를 바랍니다 . - 아 래 - ▶ 일 시 : 2020 년 07 월 22 일 ( 수 ) 07:30 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 ▶ 장 소 : 삼정호텔 2 층 라벤다 홀 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 4 만원 / 개인 회원 20 만원 이상 ( 기관회원 100 만원 이상 ) 년회비 납부하신 분은 무료입니다 . - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 *** 코로나 19 예방을 위해 열화상감지기 설치 , 손소독제 비치 , 마스크 착용 등 최선을 다하겠습니다 . ▶ 주 제: 비대면 사회의 극복을 위한 위성 및 공간정보의 역할과 비전 ▶ 연 사 : 조명희 국회의원 - 미래통합당 미래산업일자리특별위원회 위원장 - 미래창조과학부 차세대중형위성 개발사업추진위원회 위원 - 대통령 소속 국가우주위원회 위원 - 국토교통부 미래기술위원회 위원 - 과학기술부 다목적실용위성개발사업 추진위원회 위원 - 국가과학기술위원회 거대공공전문위원회 위원 ▶ 문의처 : 구교광 부회장 (010 2378 2060) 석 호익 회장 올림','2020-07-06','','','',1,63,'2020-07-06 00:00:00','2020-07-06 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2020년 정기총회 개최 알림 및 참석 요청','회원 여러분 안녕하십니까? 당초 금년 2 월 개최 예정이던 본 포럼 정기총회를 2020. 2. 5. 이사회 결의에 따라 코로나 19 사태에 대응하여 연기해오던 중 , 다음과 같이 개최하고자 하오니 회원 여러분들의 적','회원 여러분 안녕하십니까? 당초 금년 2 월 개최 예정이던 본 포럼 정기총회를 2020. 2. 5. 이사회 결의에 따라 코로나 19 사태에 대응하여 연기해오던 중 , 다음과 같이 개최하고자 하오니 회원 여러분들의 적극 참석을 부탁드립니다 . - 다 음 - 1. 일 시 : 2020 년 6 월 5 일 ( 금 ) 09:00 부터 ( 제 68 회 조찬간담회 직후 ) 2. 장 소 : 삼정호텔 신관 1 층 아도니스 홀 ( 서울시 강남구 봉은사로 150) 3. 안 건 : 가 . 2019 년도 사업추진 실적 및 결산 승인의 건 나 . 2020 년도 사업 및 예산계획 ( 안 ) 승인의 건 ※ 관련 정관 규정 : 정관 제 15 조 제 4 항 “ 총회는 회원 5 분의 1 이상의 출석으로 성회하며 , 출석 회원 과반수의 찬성으로 의결한다 .” 2020.05.28. (사)동북아공동체ICT포럼 석호익 회장 드림','2020-05-28','','\[20-13] 2020년 정기총회 개최 알림 및 참석 요청 (포럼 회원) (20.05.28).hwp [53KB]','',1,62,'2020-05-28 00:00:00','2020-05-28 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 68회 동북아공동체ICT포럼 조찬간담회 개최 안내','안녕하십니까 ? 그간 코로나 19 사태로 인해 고생많으셨습니다. 본 포럼에서는 장석영 과학기술정보통신부 차관님을 초청하여 제 68회 동북아공동체ICT포럼 조찬간담회를 아래와 같이 개최하오니 회 원 여러분들의 많은 참','안녕하십니까 ? 그간 코로나 19 사태로 인해 고생많으셨습니다. 본 포럼에서는 장석영 과학기술정보통신부 차관님을 초청하여 제 68회 동북아공동체ICT포럼 조찬간담회를 아래와 같이 개최하오니 회 원 여러분들의 많은 참석을 바랍니다 . - 아 래 - ▶ 일 시: 2020년 6월 5일 (금) 07:30 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 ▶ 장 소 : 삼정호텔 신관 1 층 Adonis 대연회장 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 4 만원 / 개인 회원 20 만원 이상 ( 기관회원 100 만원 이상 ) 년회비 납부하신 분 ( 무료 ) - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 참가신청 방법 : 메일 회신 , 전화 신청 , 문자 또는 현재 채팅방 카톡으로 신청바랍니다 . 식사 준비 , 참석자 소개 등을 위하여 반드시 사전 신청 후 참석 부탁드립니다 . 소속 ( 현 소속이 없을 경우 전 소속 ). 직위 . 성함 . 핸드폰 번호 *** 코로나 19 예방을 위해 열화상감지기 설치 . 손소독제 비치 . 마스크 착용 등 최선을 다 하겠습니다 . ▶ 연 사 : 장석영 과기정통부 제 2 차관 - 제 33 회 행정고시 합격 - 정보통신부 미래정보전략본부 유비쿼터스 정책팀 팀장 - 방송통신 위원회 국제협력관 - 미래창조과학부 정책기획관 - 과학기술정보통신부 정보통신정책실장 - 과학기술정보통신부 제 2 차관 ▶ 문의처 : 010-2378-2060( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림','2020-05-25','','','',1,61,'2020-05-25 00:00:00','2020-05-25 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2019년도 기부금 모금액 및 활용실적 보고','2019 년도 기부금 모금액 및 활용실적 보고 기부금 모금 기간 : 2019. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2019. 01. 01. ~ 12. 31. [보고 근거] - 우리 포럼은 기획재정부','2019 년도 기부금 모금액 및 활용실적 보고 기부금 모금 기간 : 2019. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2019. 01. 01. ~ 12. 31. [보고 근거] - 우리 포럼은 기획재정부장관이 지정한 지정기부금단체입니다. - 또한 사단법인 동북아공동체 ICT 포럼 정관 제 21 조 제 2 항 ( 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음연도 3 월말까지 공개한다 ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . [ 기부금 수입 ] * 수입총액 : 7,440,000 원 a. 개인 기부금 : 2,440,000 원 b. 단체 기부금 : 5,000,000 원 [ 기부금 지출 ] * 지출총액 : 7,440,000 원 1. 고유목적사업 a. 조찬간담회 : 7,440,000 원','2020-03-30','','\[고시용] 연간 기부금 모금액 및 활용실적 명세서_2019 (20.03.30).pdf [118KB]','',1,60,'2020-03-30 00:00:00','2020-03-30 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','(긴급공지: 2월12일 개최 예정인 장석영차관 초청 동북아공동체ICT 조찬 포럼 연기 통보)','(긴급공지: 2월12일 개최 예정인 장석영차관 초청 동북아공동체ICT 조찬 포럼 연기 통보) 최근 코로나 바이러스 사태와 관련 많은 회원님들의 우려와 문의가 있어 오늘 이사회에서 논의결과 일단 2월12일 조찬포럼은 ','(긴급공지: 2월12일 개최 예정인 장석영차관 초청 동북아공동체ICT 조찬 포럼 연기 통보) 최근 코로나 바이러스 사태와 관련 많은 회원님들의 우려와 문의가 있어 오늘 이사회에서 논의결과 일단 2월12일 조찬포럼은 연기하기로 했으니, 회원님들의 넓으신 양해를 구하옵니다. 회원님들 모두 건강에 유의하시고 현 사태가 진정되면 다시 날짜를 정해 알려드리겠습니다. 2020년 2월 5일 회장 석호익드림','2020-02-05','','','',1,59,'2020-02-05 00:00:00','2020-02-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 68회 조찬간담회 개최 안내','안녕하십니까 ? 과기정통부 장석영 제 2 차관님을 초청하여 동북아공동체 ICT 포럼 제 68 회 조찬 간담회 겸 포럼 정기총회를 아래와 같이 개최하고자 하오니 , 회원 여러분들의 많은 참석을 바랍니다 . ▶ 일 시 ','안녕하십니까 ? 과기정통부 장석영 제 2 차관님을 초청하여 동북아공동체 ICT 포럼 제 68 회 조찬 간담회 겸 포럼 정기총회를 아래와 같이 개최하고자 하오니 , 회원 여러분들의 많은 참석을 바랍니다 . ▶ 일 시 : 2020 년 2 월 12 일 ( 수 ) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 09:00 ~ 09:10 정기총회 ▶ 장 소 : 삼정호텔 2 층 라벤다 홀 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 5 만원 / 개인 회원 20 만원 이상 ( 기관회원 100 만원 이상 ) 년회비 납부하신 분 ( 무료 ) - 납부계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제 : ( 가칭 ) 혁신의 DNA, 과학기술 강국 ▶ 연 사 : 장석영 과기정통부 제 2 차관 ▶ 문의처 : 010-2378-2060( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림','2020-02-03','','notice.hwp [11KB]','',1,58,'2020-02-03 00:00:00','2020-02-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','동북아공동체ICT포럼 제67회 조찬간담회 참석 요청','동북아공동체ICT포럼 67회 조찬간담회 참석 요청 그간 안녕하십니까? 김연철 통일부장관님을 초청하여 동북아공동체ICT포럼 제67회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참석을 바랍니다. ','동북아공동체ICT포럼 67회 조찬간담회 참석 요청 그간 안녕하십니까? 김연철 통일부장관님을 초청하여 동북아공동체ICT포럼 제67회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참석을 바랍니다. ▶ 일 시: 2019년 12월 4일(수) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 ▶ 장 소: 삼정호텔 신관 1층 Adonis 대연회장(Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9호선 언주역 8번 출구 도보 3분 거리 | 주차 무료 ▶ 참가비: 4만원 / 개인 회원 20만원 이상(기관회원 100만원 이상) 년회비 납부하신 분(무료) - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제: 남북관계의 추진 방향 ▶ 연 사: 김연철 통일부 장관 - 1992~1996 성균관대 정치외교학과 박사 - 1997~2002 삼성경제연구소 북한연구팀 수석연구원 - 2006~2008 고려대 아세아문제연구소 연구교수 - 2017~2018 국가안보실 정책자문위원회 위원 - 2018~2019.3 통일연구원장 - 2019.4~현재 통일부 장관 ▶문의처: 010-2378-2060(구 교광 부회장) (사)동북아공동체ICT포럼 석호익 회장 올림','2019-11-11','','','',1,57,'2019-11-11 00:00:00','2019-11-11 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','(사)동북아공동체ICT포럼 제 66회 조찬간담회 개최 안내','그간 안녕하십니까? 전 정보통신부 진대제 장관님을 초청하여 동북아공동체ICT포럼 제66회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참석을 바랍니다. ▶ 일 시: 2019년 9월 24일(화) ','그간 안녕하십니까? 전 정보통신부 진대제 장관님을 초청하여 동북아공동체ICT포럼 제66회 조찬 간담회를 아래와 같이 개최하고자 하오니 회원 여러분들의 많은 참석을 바랍니다. ▶ 일 시: 2019년 9월 24일(화) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 ▶ 장 소: 삼정호텔 2층 라벤다홀(Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9호선 언주역 8번 출구 도보 3분 거리 | 주차 무료 ▶ 참가비: 4만원 / 개인 회원 20만원 이상(기관회원 100만원 이상) 년회비 납부하신 분(무료) - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제: 4차 산업혁명과 정부의 역할 ▶ 연 사: 진대제 전 정보통신부 장관 - 1983. 미국 스탠퍼드대학 전자공학 박사 - 2000. 삼성전자 디지털미디어 총괄 대표이사 - 2003~2006 정보통신부 장관 - 2013.12~ 현재 스카이레이크 인베스트먼트 CEO, 카이스트 석좌교수 ▶문의처: 010-2378-2060(구 교광 부회장) (사)동북아공동체ICT포럼 석호익 회장 올림','2019-09-10','','','',1,56,'2019-09-10 00:00:00','2019-09-10 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','ICT 남북 교류협력 활성화 방안 정책세미나 개최안내','남북 교류협력 활성화를 위한 세미나「ICT 남북 교류협력 활성화 방안 정책세미나」가 2 019년 7월 10일 (수) 14시에 국회도서관 지하 1층 강당에서 개최되오니, 회원 여러분의 많은 관심과 참석 부탁드립니다.','남북 교류협력 활성화를 위한 세미나「ICT 남북 교류협력 활성화 방안 정책세미나」가 2 019년 7월 10일 (수) 14시에 국회도서관 지하 1층 강당에서 개최되오니, 회원 여러분의 많은 관심과 참석 부탁드립니다.','2019-07-08','','\iict 남북 교류협력 활성화 방안 정책세미나.jpg [262KB]','',1,55,'2019-07-08 00:00:00','2019-07-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2019년 6월 등산모임 개최 안내','안녕하세요? 동북아공동체ICT포럼 여성/등산회장 황순연입니다. 다음 주에 있을 2019 정기산행 관련 안내드립니다. - 안 내 - 1. 일시 : 2019.6.22 (토) 09:30 ~ 14:30 (예정) 2. 장소 ','안녕하세요? 동북아공동체ICT포럼 여성/등산회장 황순연입니다. 다음 주에 있을 2019 정기산행 관련 안내드립니다. - 안 내 - 1. 일시 : 2019.6.22 (토) 09:30 ~ 14:30 (예정) 2. 장소 : 북한산 둘레길 1구간(소나무 숲길 구간) 3. 집결 : 덕성여대 앞 (지하철 4호선 수유역에서 120번,153번,1218번) 4. 준비사항 - 참가비 : 1만원(현장납부) - 편한 복장 - 개인 간식 4. 참고 블로그 https://blog.naver.com/bau83/220985959530','2019-06-10','','','',1,54,'2019-06-10 00:00:00','2019-06-10 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 65회 조찬간담회 개최 안내','그간 안녕하십니까 ? 국회 과학기술정보방송통신위원회 소속 이상민 의원님을 초청하여 동북아공동체 ICT 포럼 제 65 회 조찬 간담회를 아래와 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다 . ▶ 일 시 : 2','그간 안녕하십니까 ? 국회 과학기술정보방송통신위원회 소속 이상민 의원님을 초청하여 동북아공동체 ICT 포럼 제 65 회 조찬 간담회를 아래와 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다 . ▶ 일 시 : 2019 년 6 월 19 일 ( 수 ) 07:00 ~ 07:30 접수 및 등록 07:30 ~ 09:00 조찬 및 발표 ▶ 장 소 : 삼정호텔 2 층 라벤다홀 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 4 만원 / 개인 회원 20 만원 이상 ( 기관회원 100 만원 이상 ) 년회비 납부하신 분 ( 무료 ) - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 연 사 : 이 상민 국회의원 - 2018.11 월 ~ 현재 : 더불어민주당 정보통신특별위원회 위원장 , 과학기술특별위원회 위원장 - 2019.3~ 현재 : 국회 사법개혁특별위원회 위원장 ▶ 문의처 : 010-2378-2060( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림 " 참석 " 또는 " 불참 " 으로 회신 주시면 감사하겠습니다 .','2019-05-23','','','',1,53,'2019-05-23 00:00:00','2019-05-23 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제2회 대북 Study Group 참가 요청','4.11일 제64회 조찬 때에 알려드린 바와 같이 제2회 대북 Study Group을 아래와 같이 개최하오니 참석 희망자는 속히 연락 바랍니다. (선착순 15명) 1. 일시: 4.24(수) 오후 6시부터 7시30분 ','4.11일 제64회 조찬 때에 알려드린 바와 같이 제2회 대북 Study Group을 아래와 같이 개최하오니 참석 희망자는 속히 연락 바랍니다. (선착순 15명) 1. 일시: 4.24(수) 오후 6시부터 7시30분 2. 장소: 본 포럼 회의실(송파구 방이동 올림픽로32길 21-9) 3. 주제 및 연사: “ 캄보디아, 중국 사례로 본 대북투자 전략” 한국IT컨설팅 이 종일 상무(캄보디아,중국 에서 북한 SW인력 활용 등 사업 수행, 해외 30여개국 IT컨설팅 경험) 4. 참가비 1만원, 식사 제공 5. 연락처: 카톡에 참가신청을 직접 하시거나 02-521-8171로 연락. 동북아공동체ICT포럼 구교광 부회장 올림','2019-04-17','','','',1,52,'2019-04-17 00:00:00','2019-04-17 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2019년 4월 등산모임 개최 안내','안녕하세요? 날씨가 많이 따뜻해지고 길거리에 핀 꽃들이 제법 봄이 왔음을 느끼게 합니다. 동북아 ICT 여성·등산회에서 지난 안산 자락길 산행에 이어 다음과 같이 2019년도 2차 산행 안내 드립니다. - 다 음 -','안녕하세요? 날씨가 많이 따뜻해지고 길거리에 핀 꽃들이 제법 봄이 왔음을 느끼게 합니다. 동북아 ICT 여성·등산회에서 지난 안산 자락길 산행에 이어 다음과 같이 2019년도 2차 산행 안내 드립니다. - 다 음 - ① 일 시 : 2019년 04월 20일(토) 09:00 ~ 17:00 ② 집 결 : 09:00 까지 도착 (우천시 진행, 우의 준비) ③ 장 소 : 과천시민회관 야외공연장 (정부과천청사역 10번출구 20여 미터 좌측) ④ 코 스 : 관악산 (야외공연장~돌탑능선~철탑삼거리~자하능선 (케이블능선)~야외공연장) ⑤ 주 최 : 한국정보산업인산악회 ⑥ 참가비 : 개인 1만원 (사전입금,현장납부 모두 가능) ※ 입금 계좌 : 국민은행 578601-01-293143 (예금주:한국정보산업인산악회) ※ 입금 확인 : 조호길재무부회장 (010-8808-4386) ⑦ 참가신청 1단계) 아래 링크를 클릭하셔서 참가신청 ※ 클릭 ☞ https://forms.gle/7b9yWXNeNp1LjccD8 ※ 소속은 동북아ICT포럼으로 통일해주세요. 2단계) 카톡방에 참가신청하셨음과 참가비 납부여부를 알려 주세요^^ ⑧ 행사 시간대별 일정 09:00 ~ 09:30 등록 및 준비 09:30 ~ 10:00 대회 기념식 10:00 ~ 14:30 산행 및 점심 14:30 ~ 15:00 2부행사 (풍물놀이 등) 15:00 ~ 16:00 시상식 및 행운권 추첨 4월에도 많은 원우회원님들과 함께 꽃길을 걷고 싶습니다.','2019-04-08','','','',1,51,'2019-04-08 00:00:00','2019-04-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2018년도 재정보고 (연간 기부금 모금액 및 활용실적 보고)','2018년도 기부금 모금액 및 활용실적 보고 기부금 모금 기간 : 2018. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2018. 01. 01. ~ 12. 31. 사단법인 동북아공동체ICT포럼은 정관 제2','2018년도 기부금 모금액 및 활용실적 보고 기부금 모금 기간 : 2018. 01. 01. ~ 12. 31. 기부금 활용 기간 : 2018. 01. 01. ~ 12. 31. 사단법인 동북아공동체ICT포럼은 정관 제21조 제2항(인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음연도 3월말까지 공개한다)에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다. [기부금 수입] * 수입총액 : 2,230,000원 a. 개인 기부금 : 230,000원 b. 단체 기부금 : 2,000,000원 [기부금 지출] * 지출총액 : 2,230,000원 1. 고유목적사업 a. 조찬간담회 : 2,230,000원','2019-04-02','','\연간 기부금 모금액 및 활용실적 명세서_2018년도.pdf [431KB]','',1,50,'2019-04-02 00:00:00','2019-04-02 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2019년 춘계 등산 안내 및 참석 요청','새 봄을 맞이하여 회원 상호간의 친목을 도모하고 대화의 시간을 가지기 위하여 다음과 같이 등산행사를 개최하오니 많은 참석 부탁드립니다. - 다 음 - ■ 일 시 : 2019년 3월30일(토) 09:30 집결 / 14','새 봄을 맞이하여 회원 상호간의 친목을 도모하고 대화의 시간을 가지기 위하여 다음과 같이 등산행사를 개최하오니 많은 참석 부탁드립니다. - 다 음 - ■ 일 시 : 2019년 3월30일(토) 09:30 집결 / 14:00 해산 (예정) ■ 장 소 : 서대문구 안산 자락길 (산행 소요시간: 90분~120분 예상) ■ 집 결 : 3호선 독립문역 5번출구 밖에서 집결. ■ 참 가 비 : 10,000원 (현장 접수) ■ 점심식사 : 서대문구 한옥집(김치찜) ■ 산행준비 : 개인 지참물은 각자 준비. ■ 참가신청 : 카카오톡을 이용하여 신청해주시면 됩니다. ■ 기타 참고사항 - 서대문구 안산 자락길 산행도(독립문역 5번 출구 ~ 영천시장) - 서대문구 한옥집 정보 ■ 주최.주관 : 동북아공동체ICT 원우 여성·등산회 ■ 후 원 : (사)동북아공동체ICT포럼 많은 관심과 참여 부탁드립니다. 연락처: 구교광 부회장(010 2378 2060) 동북아공동체ICT포럼 석 호익 회장 올림','2019-03-13','','','',1,49,'2019-03-13 00:00:00','2019-03-13 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[긴급] 제 64회 조찬간담회 일정 변경 안내','안녕하십니까 ? 동북아공동체 ICT 포럼입니다. 이 효성 방송통신위원장 초청 제 64 회 조찬 간담회를 2019 년 3 월 21 일 목요일에 개최하고자 하였으나 , 많은 회원 분들이 주주총회 일정이라는 공통된 사유로','안녕하십니까 ? 동북아공동체 ICT 포럼입니다. 이 효성 방송통신위원장 초청 제 64 회 조찬 간담회를 2019 년 3 월 21 일 목요일에 개최하고자 하였으나 , 많은 회원 분들이 주주총회 일정이라는 공통된 사유로 일정 변경에 대한 문의를 주셨고 , 이에 대한 숙고와 논의 끝에 4 월 11 일 목요일로 조찬 간담회 개최를 연기하였습니다 . 조찬간담회의 성공적 개최와 회원 분들의 만족도 향상을 위해 다소 불가피한 선택이었다는 점 양해 부탁드리오며 , 간담회 관련하여 다음 내용 참고하시고 적극적인 참여 부탁드립니다 . - 다 음 - * 변경 일시 : 2019년 04월 11일 (목) | 07:30 ~ 09:00 (삼정호텔 신관 1층 Adonis 홀) * 장소와 시간은 변동이 없습니다. * 기존 일시 : 2019년 03월 21일 (목) | 07:30 ~ 09:00 2019년 3월 11일 동북아공동체ICT포럼 구교광 부회장 올림','2019-03-11','','','',1,48,'2019-03-11 00:00:00','2019-03-11 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 64회 조찬간담회 개최 안내','동북아공동체아이씨티 포럼 이효성 방통위원장 초청 제 64 차 조찬 간담회 개최 안내 안녕하십니까 ? 이 효성 방송통신위원장님을 초청하여 , “ 소 통 " 이라는 주제로 동북아공동체 ICT 포럼 제 64 회 조찬 간담','동북아공동체아이씨티 포럼 이효성 방통위원장 초청 제 64 차 조찬 간담회 개최 안내 안녕하십니까 ? 이 효성 방송통신위원장님을 초청하여 , “ 소 통 " 이라는 주제로 동북아공동체 ICT 포럼 제 64 회 조찬 간담회를 아래와 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다 . ▶ 일 시 : 2019 년 3 월 21 일 ( 목 ) 07:30 ~ 09:00 ▶ 장 소 : 삼정호텔 신관 1 층 Adonis 대연회장 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 4 만원 / 20 만원 이상 년회비 납부하신 분 ( 무료 ) - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 개인 회원의 경우에 연회비 20 만원을 내시면 4 만원이 절약되고 ( 연 6 회 조찬 *4 만원 =24 만원 ), 연회비를 기부금으로 납부하시면 개인은 연말소득공제를 , 법인은 손비처리가 가능합니다 . - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶ 주 제 : 소 통 ▶ 연 사 : 이 효성 방송통신위원장 ( 장관급 ) - 1987. 미국 NorthWestern University 언론학 박사 - 1990~ 2016 성균관대 신문방송학과 교수 - 2003~2006 방송위원회 부위원장 - 2017.08~ 현재 방송통신위원회 위원장 ▶ 문의처 : 010-2378-2060( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익회장 올림 * 참석 또는 불참으로 회신 부탁드리오며 , ( 사 ) 동북아공동체 ICT 포럼 카톡으로도 신청 가능합니다 .','2019-03-05','','','',1,47,'2019-03-05 00:00:00','2019-03-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[긴급] 제 63회 조찬간담회 일자 변경 안내','안녕하십니까? 동북아공동체ICT포럼입니다. 먼저, 제 63회 조찬간담회 관련하여 많은 성원 보내주시는 여러분께 깊은 감사의 말씀 드립니다. 하지만 연사이신 민원기 차관님의 긴급한 사안으로 인해 부득이 다음과 같이 조','안녕하십니까? 동북아공동체ICT포럼입니다. 먼저, 제 63회 조찬간담회 관련하여 많은 성원 보내주시는 여러분께 깊은 감사의 말씀 드립니다. 하지만 연사이신 민원기 차관님의 긴급한 사안으로 인해 부득이 다음과 같이 조찬간담회 겸 포럼 총회 일자를 변경하게 되어 대단히 죄송합니다. 필히 확인하시어 착오 없으시길 바랍니다. 변경된 일자(2월 21일 (목))에 참석하실 수 있는지 연락 부탁드립니다. - 다 음 - * 변경 일시 : 2019년 02월 21일 (목) | 07:30 ~ 09:10 (삼정호텔 신관 1층 Adonis 홀) * 장소와 시간은 변동이 없습니다. * 기존 일시 : 2019년 02월 20일 (수) | 07:30 ~ 09:10 2019년 2월 15일 동북아공동체ICT포럼 구교광 부회장 올림','2019-02-15','','','',1,46,'2019-02-15 00:00:00','2019-02-15 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제 63회 조찬간담회 및 정기총회 개최 안내','*** 긴급공지 *** 일자의 변동이 있습니다. 종전 2월 20일에서 21일로 변경되었으니 확인하시고 착오없으시기 바랍니다. 감사합니다. ----- 주제 : 사람 중심의 4 차산업혁명 실현 (2019 년 과기정통부 ','*** 긴급공지 *** 일자의 변동이 있습니다. 종전 2월 20일에서 21일로 변경되었으니 확인하시고 착오없으시기 바랍니다. 감사합니다. ----- 주제 : 사람 중심의 4 차산업혁명 실현 (2019 년 과기정통부 주요업무계획 ) 일시 : 2019 년 02 월 21 일 (목 ) 07:30 ~ 09:10 (* 변경) 발표 : 민원기 과기정통부 차관 그간 안녕하십니까 ? 본 포럼에서는 민 원기 과기정통부 제 2 차관님을 초청하여 제 63 회 조찬 간담회 및 정기총회를 다음과 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다 . - 다 음 - ▶ 일 시 : 2019 년 02 월 20 일 ( 수 ) 07:30 ~ 09:10 ▶ 장 소 : 삼정호텔 신관 1 층 Adonis 대연회장 (Tel 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9 호선 언주역 8 번 출구 도보 3 분 거리 | 주차 무료 ▶ 참가비 : 4 만원 / 연회비 (20 만 원 이상 ) 납부하신 분은 무료입니다 . - 계좌번호 : 하나은행 103 - 910044 - 13304 ( 예금주 : 동북아공동체 ICT 포럼 ) - 개인 회원의 경우 , 연회비 20 만 원을 내시면 4 만 원이 절약 ( 연 6 회 조찬 참석비 : 6 회 *4 만원 = 24 만원 ) 되고 연회비를 기부금으로 납부하시면 개인은 연말소득공제를 , 법인은 손비처리를 받을 수 있습니다 . - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능합니다 . ▶ 연 사 : 민 원기 과기정통부 제 2 차관 - 2016.11 ~ 현 재 : 경제협력개발기구 (OECD) 디지털경제정책위원회 의장 - 2015.05 ~ 2016. 05: 국제전기통신연합 (ITU) 이사회 의장 - 2015: 미래창조과학부 기획조정실장 ▶ 정기 이사회 안건 : 2018 년 사업추진 실적 및 결산 승인의 건 , 2019 년 사업 및 예산계획 ( 안 ) 승인의 건 ▶ 문의처 : 010-2378-2060( 구 교광 부회장 ) ( 사 ) 동북아공동체 ICT 포럼 석호익 회장 올림 * 사전접수 필히 부탁드립니다 . * 조찬 발표 후 포럼 정기총회가 있사오니 회원님들의 적극적인 참여를 부탁드립니','2019-02-12','','','',1,45,'2019-02-12 00:00:00','2019-02-12 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[안내] (사)동북아공동체ICT포럼 사무실 이전 안내','안녕하십니까. 동북아공동체ICT포럼입니다. 2019년 1월 10일자로 본 포럼 사무실이 이전하게 되어 포럼 회원 여러분들께 안내드리오니 참고하시기 바랍니다. 기존 주소 : 서울 서초구 서초중앙로 69 르네상스빌딩 1','안녕하십니까. 동북아공동체ICT포럼입니다. 2019년 1월 10일자로 본 포럼 사무실이 이전하게 되어 포럼 회원 여러분들께 안내드리오니 참고하시기 바랍니다. 기존 주소 : 서울 서초구 서초중앙로 69 르네상스빌딩 1505호 이전 후 주소 : 서울 송파구 올림픽로32길 21-9 2층 (시스텍전기통신 건물 2층) 연락처 : 02-521-8171(동북아공동체ICT포럼 구교광 부회장)','2019-01-11','','\map.png [86KB]','',1,44,'2019-01-11 00:00:00','2019-01-11 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[홍보/행사안내] IITP Special Winter Concert 개최','안녕하십니까, 동북아공동체ICT포럼입니다. 과학기술정보통신부 산하 정보통신기술진흥센터에서 11월 23일 금요일 양재 엘타워에서 남북 ICT관련 행사를 진행합니다. 회원 여러분들의 많은 관심과 참석 부탁드립니다. 아래','안녕하십니까, 동북아공동체ICT포럼입니다. 과학기술정보통신부 산하 정보통신기술진흥센터에서 11월 23일 금요일 양재 엘타워에서 남북 ICT관련 행사를 진행합니다. 회원 여러분들의 많은 관심과 참석 부탁드립니다. 아래의 포스터를 클릭하시거나 게재된 링크를 통해 행사에 사전등록하실 수 있습니다. 감사합니다. -------------------------------------------------------------------------------- IITP(정보통신기술진흥센터) 주관으로 "IITP 스폐셜 윈터 콘서트" 를 개최하오니 많은 참여 부탁 드립니다. ㅇ 등록 사이트 : https://www.onoffmix.com/event/158206','2018-11-16','','','',1,43,'2018-11-16 00:00:00','2018-11-16 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제62회 조찬 간담회 겸 임시총회 개최 안내','그간 안녕하십니까? 동국대학교 김용현 교수님을 초청하여 "평양정상회담과 한반도 정세 전망"이라는 주제로 제62회 조찬 간담회 겸 임시총회를 아래와 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다. ▶일 시: 2','그간 안녕하십니까? 동국대학교 김용현 교수님을 초청하여 "평양정상회담과 한반도 정세 전망"이라는 주제로 제62회 조찬 간담회 겸 임시총회를 아래와 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다. ▶일 시: 2018년 11월 22일(목) 07:30 ~ 09:00 ▶장 소: 한국프레스센터 18층 외신기자클럽 (Tel. 02-2001-7114) - 서울시 중구 태평로 1가 25 | - 지하철 1호선 서울시청역. 2호선 서울시청역.을지로입구역.5호선 광화문역 | 주차 무료 ▶참가비: 3만원 / 20만원 이상 년회비 납부하신 분(무료) - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶주 제: 평양정상회담과 한반도 정세 전망 ▶연 사: 김 용현 동국대 교수 - 동국대 대학원 정치학 박사 - 2018.07~ 국가안보실 정책자문위원회 위원 - 2018.05~ KBS 객원해설위원 - 2018.03 남북정상회담 준비위원회 전문가 자문단 - 2017.08~ 통일부 남북교류협력추진위원회 위원 ▶ 임시총회 회의 안건: 포럼 임원임기만료에 따른 임원 선임의 건 ▶문의처: 010-2378-2060(구 교광 부회장) ▶ 참석, 불참 여부를 문자로 알려주시면 감사하겠습니다. (사)동북아공동체ICT포럼 석호익회장 올림','2018-11-14','','','',1,42,'2018-11-14 00:00:00','2018-11-14 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','「남북한 ICT 및 문화 교류에 대한 현황과 전망」개최 안내','포럼 회원 여러분, 안녕하십니까? 동북아공동체ICT포럼이 후원하는 2018학년도 서울과학기술대학교 IT정책전문대학원 세미나 「남북한 ICT 및 문화 교류에 대한 현황과 전망 」2018년 10월 23일 화요일 13시 ','포럼 회원 여러분, 안녕하십니까? 동북아공동체ICT포럼이 후원하는 2018학년도 서울과학기술대학교 IT정책전문대학원 세미나 「남북한 ICT 및 문화 교류에 대한 현황과 전망 」2018년 10월 23일 화요일 13시 30분부터 18시까지 국회 의원회관 제1세미나실에서 개최되오니, 회원 여러분의 많은 관심과 참석 부탁드립니다. ▷ 문의 : 02-970-6795(서울과학기술대학교 IT정책전문대학원)','2018-10-15','','20181023poster.jpg [2623KB]','',1,41,'2018-10-15 00:00:00','2018-10-15 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','(사)동북아공동체ICT포럼 10월13일 등산행사 안내','흘러가는 구름들은 어디로 몰려가는지,높고 파란 하늘을 하염없이 바라보게 합니다.가을은 이렇게 익어가고 불어오는 바람은 은은한 커피향을 담고 있는듯한 시간입니다. 잠시나마 마음의 여유를 가져보고 그리운 얼굴들을 만나보','흘러가는 구름들은 어디로 몰려가는지,높고 파란 하늘을 하염없이 바라보게 합니다.가을은 이렇게 익어가고 불어오는 바람은 은은한 커피향을 담고 있는듯한 시간입니다. 잠시나마 마음의 여유를 가져보고 그리운 얼굴들을 만나보기위서 아래와 같이 관악산 마당바위를 올라 보고자 하오니 참석 바랍니다. - 아 래 - ■ 일 시 : 10월 13일(토), 10:00 ※ 집결 : 2호선 사당역 안, 『만남의 광장』집결 후 함께 이동 ■ 장 소 : 관악산(사당역-선유샘터-마당바위-417봉(헬기장)-하산) ■ 참가비 : 1만원 ■ 준비물 : 생수 및 간식 ■ 점 심 : 이바돔감자탕 14:00(예약 예정) (사당역 5번출구 근처, 식당전화:02-525-4664, 식당주소: 관악구 남현동 1062-15, 2층) ■ 문 의 : 등산회 회장(최 성 교수, 010-3390-2062) 총무(정보통신공사협회 김순호 팀장, 010-4525-5251) 포럼(구교광 부회장, 010-2378-2060) ※ 참석 가능하신 분들 꼭 카톡 댓글에 이름 남겨 주세요. - 등산이 어려우신 분들은 식사만 참여가능합니다.','2018-10-10','','','',1,40,'2018-10-10 00:00:00','2018-10-10 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[안내] 한스 모드로 前 동독 총리 초청 강연 개최','안녕하십니까. 동북아공동체ICT포럼입니다. 북한대학원대학교에서 진행되는 한스 모드로 전 총리 강연 관련 안내입니다. 관심있는 분들의 많은 참석 부탁드립니다. 감사합니다. _________________________','안녕하십니까. 동북아공동체ICT포럼입니다. 북한대학원대학교에서 진행되는 한스 모드로 전 총리 강연 관련 안내입니다. 관심있는 분들의 많은 참석 부탁드립니다. 감사합니다. ________________________________________________________________________________________________ 안녕하세요. 북한대학원대학교 SSK남북한마음통합연구센터입니다. 연구센터가 오는 17일(월) 본교 대회의실에서 한스 모드로 전 독일 총리의 강연 ''통일 독일의 경험과 한반도에의 함의''를 개최합니다. 한스 모드로 전 총리는 통일 전 동독 정치인으로, 공산당의 마지막 수장을 지냈습니다. 이번 강의에서 한반도 정세와 북한의 변화, 통일 독일의 경험을 전할 예정입니다. 여러분의 많은 참여와 관심 부탁드립니다. * 행사개요 - 일 시 : 2018. 9. 17(월), 16:00~18:00 - 장 소 : 북한대학원대학교 대회의실(평화관 1층) - 연 사 : 한스 모드로 전 동독 총리 - 내 용 : 한반도 정세 및 북한 변화, 통일독일 경험 강의 - 기 타 : 본 강의는 독일어로 진행되며, 한국어 통역이 제공됩니다. - 문 의 : 북한대학원대학교 SSK연구센터 조교 최종환 02-3700-0859 / jhlove2412@naver.com','2018-09-11','','','',1,39,'2018-09-11 00:00:00','2018-09-11 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[안내]남북 ICT 협력 정책 세미나 「함께 만드는 디지털 평화! 디지털 번영!」 개최 안내','안녕하십니까, 동북아공동ICT포럼입니다. 9월 12일 수요일 국회의원회관에서 진행되는 남북ICT협력 정책세미나 관련 안내입니다. 참고하시기 바랍니다. ____________________________________','안녕하십니까, 동북아공동ICT포럼입니다. 9월 12일 수요일 국회의원회관에서 진행되는 남북ICT협력 정책세미나 관련 안내입니다. 참고하시기 바랍니다. __________________________________________________________________________ 남북 관계가 점차 개선됨에 따라 ICT 분야에서 남북한 간 효과적인 협력을 준비하기 위해 남북 ICT 협력 정책 세미나 를 준비하였습니다. o 주 제 : 남북 ICT 협력 정책 세미나 「함께 만드는 디지털 평화! 디지털 번영!」 o 일 시 : 2018.9.12(수), 9시30분~12시 o 장 소 : 국회의원회관 제2세미나실 바쁘시겠지만 많은 관심과 참석 부탁 드립니다. 사전등록 페이지: .( https://onoffmix.com/event/150753 ) >','2018-09-04','','남북ict협력세미나_안내포스터.jpg [1046KB]','',1,38,'2018-09-04 00:00:00','2018-09-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','동북아공동체ICT포럼 제61회 조찬 간담회초청 (양문수 북한대학원대학교 부총장 초청 강연회)','그간 안녕하십니까? 금년 여름 무더위에 수고 많으셨습니다.국내 최고의 북한 경제 전문가인 북한 대학원대학교 양 문수 부총장님을 초청하여, “북한 비핵화에 따른 신남북경협시대의 개막: 전망과 과제”라는 주제로 동북아공','그간 안녕하십니까? 금년 여름 무더위에 수고 많으셨습니다.국내 최고의 북한 경제 전문가인 북한 대학원대학교 양 문수 부총장님을 초청하여, “북한 비핵화에 따른 신남북경협시대의 개막: 전망과 과제”라는 주제로 동북아공동체ICT포럼 제61회 조찬 간담회를 아래와 같이 개최하고자 하오니 참석하여 주시면 감사하겠습니다. ▶일 시: 2018년 9월 11일(화) 07:30 ~ 09:00 ▶장 소: 삼정호텔 2층 라벤다 홀 (Tel. 02-557-1221) - 서울시 강남구 봉은사로 150 | 서울시 강남구 역삼동 604-11 - 지하철 9호선 언주역 8번 출구 도보 3분 거리 | 주차 무료 ▶참가비: 3만원 / 20만원 이상 년회비 납부하신 분(무료) - 계좌번호 : 하나은행 103 - 910044 - 13304 (예금주: 동북아공동체 ICT포럼) - 부득이 사전 납부를 못하신 분은 당일 현장에서 현금 또는 신용카드로 납부 가능 ▶주 제: "북한 비핵화에 따른 신남북경협시대의 개막: 전망과 과제” ▶연 사: 양문수 북한대학원 대학교 부총장 - 서울대 경제학사. 일본 도쿄 대학 경제학 석사 및 박사 - 매일경제, 문화일보 기자 - LG경제연구원 부연구위원 - 민주평화통일 자문회의 상임위원 - 현재 북한대학원 대학교 교수,통일부 정책자문위원, KBS통일방송연구자문위원회 자문위원 - 저서: 글로벌 거버넌스와 북한의 법제도, 북한 경제 구조 등 ▶문의처: 010-2378-2060(구 교광 부회장)','2018-08-27','','','',1,37,'2018-08-27 00:00:00','2018-08-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','동북아지역 IoT 주파수 공동이용을 위한 동향분석 및 기술표준 방향연구 세미나 안내','안녕하십니까. 동북아공동체ICT포럼입니다. 본 포럼에서는 금주 7월6일 금요일 오후 2시부터 ETRI 서울사무소(서초구 서초중앙로 63. 리더스빌딩 6층)에서 다음과 같이 IoT관련 세미나를 개최하오니, 관심 있는 ','안녕하십니까. 동북아공동체ICT포럼입니다. 본 포럼에서는 금주 7월6일 금요일 오후 2시부터 ETRI 서울사무소(서초구 서초중앙로 63. 리더스빌딩 6층)에서 다음과 같이 IoT관련 세미나를 개최하오니, 관심 있는 분은 사전에 연락주시고많은 참석 바랍니다. 문의 : 동북아공동체ICT포럼 구교광 부회장(010 2378 2060) __________________________________________________________________________________________','2018-07-04','','','',1,36,'2018-07-04 00:00:00','2018-07-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','「남북 ICT 교류협력 방안 정책 세미나」개최 안내','포럼 회원님, 그간 안녕하십니까? 동북아공동체ICT포럼에서는 한국정보통신공사협회와 공동주관으로 「 남북 ICT 교류협력 방안 정책 세미나 」 를 아래와 같이 개최하오니, 회원 여러분의 많은 관심과 신청 부탁드립니다.','포럼 회원님, 그간 안녕하십니까? 동북아공동체ICT포럼에서는 한국정보통신공사협회와 공동주관으로 「 남북 ICT 교류협력 방안 정책 세미나 」 를 아래와 같이 개최하오니, 회원 여러분의 많은 관심과 신청 부탁드립니다. ▷ 일시 : 2018년 7월 6일(금) 09:00 - 12:10 ▷ 장소 : 국회의원회관 제2소회의실 ▷ 발제 - 북한의 ICT인프라 현황 및 교류협력 방안(최성, 남서울대 교수) - 남북한 ICT 교류협력 방안(이상산, (주)핸디소프트 부회장) - 정보통신공사업 분야의 남북 교류협력 방안 및 역할(표창균, 한국정보통신산업연구원 박사) - 남북 디지털 콘텐츠 교류협력 방안(남한길, EBS 글로벌사업부 PD) ▷ 종합토론 - 좌장 : 임주환(한국정보통신산업연구원 원장) - 패널 : 박찬모(평양과학기술대학교 명예총장), 유완영(세한대학교 특임부총장), 김순용((주)KT 상무), 전진우(시스텍전기통신(주) 대표이사), 김흥광(NK지식인연대 대표) ▷ 문의 031-231-3422, ksk@kici.re.kr','2018-06-20','','\poster.jpg [945KB]','',1,35,'2018-06-20 00:00:00','2018-06-20 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[홍보요청]2018년도 이공계전문기술연수사업(한국IT전문가협회)','* 과학기술정보통신부 후원으로 시행하는 사업의 홍보 요청이 있어서 안내드립니다.(동북아공동체ICT포럼 사무국) __________________________________________________________','* 과학기술정보통신부 후원으로 시행하는 사업의 홍보 요청이 있어서 안내드립니다.(동북아공동체ICT포럼 사무국) _________________________________________________________________________________________ 안녕하십니까 ? 한국IT전문가협회 사무국입니다. 협회에서는 “2018년도 이공계전문기술연수사업”의 연수생을 모집 중 입니다. 본 사업은 이공계 대졸 미취업자 에게 현장 연수 등 직업교육 기회를 제공함으로써 실무능력을 강화하여 청년실업 문제 및 이공계 인력의 수급 불균형을 해소하기 위한 목적으로 진행되는 과학기술정보통신부 시행 사업입니다. 18주동안의 전문연수교육과 4주간의 기업연수를 마친 후 취업까지 연계하는 프로그램으로 미취업자 맞춤 교육입니다. □ 연수분야 : 자바 FRAMEWORK 기반 웹 응용SW 개발자 양성과정 □ 연수기간 : 2018.06.11 ~ 11.20(22주), 일 5시간씩 총 550시간 교육 □ 교육인원 : 60명 (선착순 마감) □ 교육대상 : 이공계 대졸(전문대졸 포함, ''18.08 졸업예정자 가능) 미취업자로서 ''84.01.01 이후 출생자 □ 연 락 처 : IPAK 사무국(02-338-2311, ipak@ipak.or.kr ) ※ 전액 무료 교육, 월 30만~50만원 연수수당 지급 감사합니다.','2018-06-01','','','',1,34,'2018-06-01 00:00:00','2018-06-01 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제4기 통일ICT전문가 교육 안내','안녕하십니까. 동북아공동체ICT포럼입니다. 남북정상회담에 이은 6월 북미정상회담 후에 활발한 남북교류가 예상되는 이 때에 제4기 통일ICT전문가과정을 6월14일부터 11강과정으로 시작합니다. 회원 여러분, 5월31일','안녕하십니까. 동북아공동체ICT포럼입니다. 남북정상회담에 이은 6월 북미정상회담 후에 활발한 남북교류가 예상되는 이 때에 제4기 통일ICT전문가과정을 6월14일부터 11강과정으로 시작합니다. 회원 여러분, 5월31일까지 수강생을 모집하오니 좋은 수강생을 적극 추천 부탁드립니다. 많이 추천해주신 분에게는 감사장과 상품도 드립니다. 8월15일부터 19일까지 백두산 블라디보스톡 현지 답사를 가실 분은 미리 신청바랍니다. 구교광 부회장 올림','2018-05-16','','2018 ict전문가교육_수강신청서.pdf [593KB]','',1,33,'2018-05-16 00:00:00','2018-05-16 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','(사)동북아공동체ICT포럼 등산행사 일정 변경 안내','안녕하십니까? 동북아공동체ICT포럼입니다. 내일 4월 14일(토) 강수확률이 60프로 이상이고 기온이 많이 떨어진다고 하여 산악회 회장, 총무님과 협의한 결과, 예정되었던 등산행사를 부득이하게 다음과 같이 변경해 실','안녕하십니까? 동북아공동체ICT포럼입니다. 내일 4월 14일(토) 강수확률이 60프로 이상이고 기온이 많이 떨어진다고 하여 산악회 회장, 총무님과 협의한 결과, 예정되었던 등산행사를 부득이하게 다음과 같이 변경해 실시 하려 하오니 회원 여러분의 이해와 많은 참여를 부탁드립니다. ※ 4월 21일(토) 정보산업인 한마음 등반행사에 단체팀으로 참가 1. 일시 : 2018.4.21(토) 09:30 ~ 17:00 (우천시도 진행) 2. 행사일정 ▶​ 등록/준비 : 09:00 ~ 09:30 ▶ 기념행사 : 09:30 ~10:00 ▶ 산행/점심 : 10:00 ~14:30 (식사 주최측 제공) ​ ▶ 자유시간 : 14:30 ~15:00 ​ ▶ 시상식 및 행운권 추첨 : 15:00 ~16:00 3. 집결장소 : 과천시민회관 야외공연장 (정부과천청사역 10번출구 20여 미터 좌측) 4. 산행코스 : 관악산 6KM (행사장~돌탑능선~철탑삼거리~자하능선(케이블능선)~행사장) 5. 주최 : 한국정보산업인산악회 6. 공동주관 : 세종텔레콤, 한국IT전문가협회, 하이테크정보, 코리아아이티타임즈 7. 사전등록 : 4.18(수) 마감 8. 참가비용 : 1인 1만원 9. 준비물 : 생수, 간식 ​10. 지난해에도 이 행사에 본 포럼에서 단체팀으로 참가하였습니다. 참가를 희망하시는 분은 4월 18일 수요일까지 연락부탁드립니다. ​ [연락처] 동북아공동체ICT 포럼 산악회장 최성 교수 : 010-2909-1400 동북아공동체ICT 포럼 산악회 총무 김순호 팀장 : 010-4525-5251 동북아공동체ICT 포럼 구교광 부회장 : 010-2378-2060','2018-04-13','','','',1,32,'2018-04-13 00:00:00','2018-04-13 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','(사)동북아공동체ICT포럼 등산행사 안내','안녕하십니까? 어느덧 새 싹이 돋아나고 꽃이 만개하는 완연한 새 봄, 사월이 왔습니다.지난 3월16일 조찬세미나 겸 포럼 총회에서 안내드렸듯이, 포럼 회원상호간의 정보교류와 친목도모를 위한 "4월등산모임"을 아래와 ','안녕하십니까? 어느덧 새 싹이 돋아나고 꽃이 만개하는 완연한 새 봄, 사월이 왔습니다.지난 3월16일 조찬세미나 겸 포럼 총회에서 안내드렸듯이, 포럼 회원상호간의 정보교류와 친목도모를 위한 "4월등산모임"을 아래와 같이 안내드리오니 회원 여러분의 많은 참여를 부탁드립니다. 참가 희망을 하시는 분은 4월10(화)까지 적극 신청 바라오며,부득이한 사정으로 저녁 식사에만 참석하실 분도 사전에 신청부탁드립니다. ▶일 시: 2018년 4월 14(토) 오후 2시 2호선 사당역 안 만남의 광장 에서 집결 ▶장 소: 관악산(사당역-선유샘터-마당바위-417봉(헬기장)-하산) ▶참가비:1만원 ▶준비물: 생수 및 간단한 간식거리 ▶기타: 오후 5시30분경 저녁식사 제공( 이바지돔 감자탕:관악구 남현동 1062-15.2층.02-525-4664) 사당역 5번 출구 도보 1분 ▶문의처: 등산회 회장(최 성 교수 010-3390-2062) 등산회 총무(정보통신공사협회 김순호 팀장 010-4525-5251) 포럼 구 교광 부회장(010-2378-2060) * 연간 계획:연간 3회 등산 실시 (4월, 6월, 10월) 매 두번째 토요일 (사)동북아공동체ICT포럼 석호익 회장 올림','2018-04-04','','','',1,31,'2018-04-04 00:00:00','2018-04-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2017년도 기부금 모금 및 활용실적 보고','2017 년도 기부금 모금액 및 활용실적 기부금 모금 기간 : 2017.1.1.~12.31 기부금 활용 기간 : 2017.1.1.~12.31 사단법인 동북아공동체ICT포럼은 정관 제 21 조 제2 항 (법인은 법인 ','2017 년도 기부금 모금액 및 활용실적 기부금 모금 기간 : 2017.1.1.~12.31 기부금 활용 기간 : 2017.1.1.~12.31 사단법인 동북아공동체ICT포럼은 정관 제 21 조 제2 항 (법인은 법인 및 국세청의 인터넷 홈페이지를 통해 연간 기부금 모금액 및 활용실적을 다음 연도 3월31일까지 공개한다. ) 에 의거하여 다음과 같이 기부금 모금액 및 활용실적을 보고합니다 . ﻿ 【 기부금 수입 】 ● 수입총액 : 0원 【 기부금 지출 】 ● 지출총액 : 0 원 ※ 자세한 내용은 국세청홈페이지에서도 확인하실 수 있습니다 .','2018-04-03','','\연간 기부금 모금액 및 활용실적 명세서.pdf [120KB]','',1,30,'2018-04-03 00:00:00','2018-04-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','제60회 동북아공동체ICT포럼 조찬간담회 개최결과','□ 행사결과 ㅇ 동북아공동체 ICT 포럼 제 60 차 조찬을 기념하기 위하여 반기문 前 UN 사무총장을 초청하여 평창 동계올림픽과 한반도 정세라는 주제로 강연을 청취한 후 회원들과 교류를 가짐 □ 행사개요 ㅇ 일 시','□ 행사결과 ㅇ 동북아공동체 ICT 포럼 제 60 차 조찬을 기념하기 위하여 반기문 前 UN 사무총장을 초청하여 평창 동계올림픽과 한반도 정세라는 주제로 강연을 청취한 후 회원들과 교류를 가짐 □ 행사개요 ㅇ 일 시 : 2018. 3. 16 ( 금 ) 07:30 ~ 09:30 ㅇ 장 소 : 서울 삼정호텔 1 층 아도니스 홀 ㅇ 주 최 : 동북아공동체 ICT 포럼 ㅇ 참석자 : 동북아공동체 ICT 포럼 석호익 회장 , 동북아공동체 ICT 포럼 회원 등 100 여명 □ 보도자료 일 자 기 사 명 신문사명','2018-03-21','','','',1,29,'2018-03-21 00:00:00','2018-03-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','북,중,러 접경지역 답사 참가자를 모집합니다.','본 포럼에서는 8월10(목)부터 8월14일(월)까지 북,중,러 접경지역 현지 답사를 진행합니다. 현지 답사에 많은 신청 부탁드립니다. - 북·중·러 접경지역 ( 두만강 입구에서 압록강 입구까지 ) 현지 답사 희망자는','본 포럼에서는 8월10(목)부터 8월14일(월)까지 북,중,러 접경지역 현지 답사를 진행합니다. 현지 답사에 많은 신청 부탁드립니다. - 북·중·러 접경지역 ( 두만강 입구에서 압록강 입구까지 ) 현지 답사 희망자는 7.26( 수 ) 까지 동북아공동체 ICT 포럼 구 교광 부회장에게 “ 여권 사본 ” 을 이메일 송부바랍니다 . bismak0308@naver.com 010-2378-2060 - 답사 경비 127 만원은 7.28( 금 ) 까지 하나은행 281-890061-91204( 예금주 : 동북아공동체 ICT 포럼 ) 으로 송금 요청 . 단체비자 발급비 45,000 원 별도 - 상기 일정과 비용은 항공사 사정 등 부득이한 경우에는 일부 변경될 수 있음을 미리 양해 부탁드립니다 .','2017-07-21','','1c9f03ec011b58187baab0c8949e8084_1.jpg [131KB]','',1,28,'2017-07-21 00:00:00','2017-07-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일ICT전문가교육 제3기 교육생을 모집합니다.','1. 동북아공동체ICT포럼(구.통일IT포럼.회장:석호익 전 KT부회장)에서는 향후 남북 관계 활성화시기에 대비한 “통일ICT전문가 교육”을 이 달 6월 29부터 9월 7일까지 매주 목요일 저녁 7시부터 2시간씩 실시','1. 동북아공동체ICT포럼(구.통일IT포럼.회장:석호익 전 KT부회장)에서는 향후 남북 관계 활성화시기에 대비한 “통일ICT전문가 교육”을 이 달 6월 29부터 9월 7일까지 매주 목요일 저녁 7시부터 2시간씩 실시합니다. 2. 남북관계 경색 등으로 한국 ICT기업이 북한에 진출하지 못하는 동안 중국·이집트·싱가폴·네덜란드 등 외국 기업은 북한에 진출하여 사업을 하고 있고 앞으로 확대될 소지가 크기 때문에, 이에 대응해서 ICT관련 통일전문가를 사전에 양성해 남북관계 활성화 시기에 대비할 필요성이 높아지고 있습니다. 3. 교수진은 과거에 북한과 실제로 ICT사업 노하우가 있는 경험자 위주로 위촉을 완료하였고, 교류협력 전문가, 협력사업 개발 전문가, 교육 전문가, 설치·운영 전문가, 유지·보수 전문가 등을 양성하기 위하여 미래창조과학부의 지원을 받아 전문 교육을 실시합니다. 지원자격은 정부기관, 언론, 학계, 정당, 기업체, 군, 공공기관 등의 지도층 인사 및 이와 동등한 자격을 갖춘 자이고, 교육장소는 지방에서의 접근성이 용이한 한국 정보통신공사협회(용산구 갈월동 16번지 소재)이며, 수강료는 30만원(해외연수비 별도), 대학(원)생 10만원(해외연수비 별도)입니다. 4. 붙임 자료를 참조하셔서 많이 등록하여 주시면 감사하겠습니다. 5. 연락처: 02)521-8171 구교광 부회장 bismak0308@naver.com 02)598-8177 권다희 연구원 Fax : 02-521-8730 6. 수강신청서 다운로드: http://attach.mail.daum.net/bigfile/v1/urls/d/l3ZsUZahkfqe5rUzIF9EF308cvc/6pXmG19hIf3uhxinBhLSGQ','2017-06-02','','수강신청서.hwp [21KB]','',1,27,'2017-06-02 00:00:00','2017-06-02 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','‘남북 ICT교류 활성화 포럼’ 개최안내','‘남북 ICT교류 활성화 포럼’ 개최안내','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2014-05-23','','','',1,26,'2014-05-23 00:00:00','2014-05-23 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[공지] 동북아공동체ICT포럼 회원가입신청서','안녕하세요. 동북아공동체ICT포럼 회원가입 문의가 많아서 공지드립니다. 첨부된 포럼 회원가입신청서를 작성해주시고, 사무국( tongilforum@naver.com )으로 메일 보내주시면 확인후 연락드리도록 하겠습니다','안녕하세요. 동북아공동체ICT포럼 회원가입 문의가 많아서 공지드립니다. 첨부된 포럼 회원가입신청서를 작성해주시고, 사무국( tongilforum@naver.com )으로 메일 보내주시면 확인후 연락드리도록 하겠습니다. 많은 관심에 감사드립니다. 회원가입신청서 다운받기 : http://attach.mail.daum.net/bigfile/v1/urls/d/8H-z4C1BmbJ45DmxtS88vkIvsag/ooNC5fS5a0EiMXrcjp03Aw','2014-03-03','','','',1,25,'2014-03-03 00:00:00','2014-03-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2014년도 통일IT포럼 조찬간담회','2014년도 통일IT포럼 조찬간담회','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2014-01-10','','','',1,24,'2014-01-10 00:00:00','2014-01-10 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2013년 통일IT포럼 신년교류회 개최결과','□ 행사목적 ㅇ 새 정부 출범을 앞두고 IT부문 통일정책 공감대를 형성하고, 정부정책 수립에 필요한 의견제시를 하기 위함 □ 행사개요 ㅇ 일 시 : 2013. 1. 15(화) 10:30 ~ 13:30 (오찬 포함) ','□ 행사목적 ㅇ 새 정부 출범을 앞두고 IT부문 통일정책 공감대를 형성하고, 정부정책 수립에 필요한 의견제시를 하기 위함 □ 행사개요 ㅇ 일 시 : 2013. 1. 15(화) 10:30 ~ 13:30 (오찬 포함) ㅇ 장 소 : 프레스센터 19층 매화홀 ㅇ 주 최 : 통일IT포럼 ㅇ 후 원 : 지식경제부, 방송통신위원회, 전자신문, 조선경제i ㅇ 참석자 : 통일IT포럼 석호익 회장, 연변과기대 김진경 총장, 지경부 윤상직 차관, 방통위 김충식 상임위원, 국회 김장실 의원 및 통일IT포럼 회원 등 170여명 □ 언론보도 일 자 기사명 신문사명 링크 ‘13.01.15 통일 IT 포럼 , 신년교류회서 남북교류 필요성 논의 조선비즈 http://biz.chosun.com/site/data/html_dir/2013/01/15/2013011501544.html “ 통일 IT 포럼 신년교류회 연합뉴스 http://media.daum.net/society/others/newsview?newsid=20130115124912377 “ 통일 IT 포럼 " 민간 차원 기술 교류로 통일 실현해야 " 전자신문 http://media.daum.net/digital/others/newsview?newsid=20130115155118785 “ 경색된 남북관계 해소 , IT 교류 협력이 해법 아이뉴스 24 http://news.inews24.com/php/news_view.php?g_serial=717740&g_menu=020100 “ 평양과기대 총장 " 박근혜 정부에 큰 기대 " 연합뉴스 http://www.yonhapnews.co.kr/bulletin/2013/01/15/0200000000AKR20130115112300014.HTML?did=1179m “ 신년교류회 참석한 김진경 총장 연합뉴스 http://media.daum.net/society/others/newsview?newsid=20130115124910375 “ 평양과기대 김진경 총장 " 박근혜 정부에 기대 " MBN http://mbn.mk.co.kr/pages/news/newsView.php?category=mbn00006&news_seq_no=1289110 “ 포토 ] 발언하는 평양과기대 김진경 총장 천지일보 http://www.newscj.com/news/articleView.html?idxno=167546 “ 평양과기대 김진경 “ 정치적 통일보다 문화 · 정서적 통일 이루자 ” 천지일보 http://www.newscj.com/news/articleView.html?idxno=167562 ‘13.01.14 석호익 통일 IT 포럼 회장 , 15 일 신년교류 세미나 전자신문 http://media.daum.net/breakingnews/newsview?newsid=20130114115121698 ‘13.01.11 통일 IT 포럼 , 15 일 남북 IT 협력을 위한 신년 교류회 열어 조선비즈 http://biz.chosun.com/site/data/html_dir/2013/01/11/2013011101259.html “ 통일 IT 포럼 , 15 일 신년교류회 " 남북한 IT 산업 표준화 협력센터 설립 등 제안 " 전자신문 http://media.daum.net/digital/internet/newsview?newsid=20130111154612476','2013-08-08','','','',1,23,'2013-08-08 00:00:00','2013-08-08 00:00:00');
