INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 11/21 정책간담회 개최결과 (0)','포럼 활성화 방안 협의를 위한 간담회를 개최하고 그 결과를 아래와 같이 보고합니다. - 아 래 - 가. 일시 : 2012.11.21.(수) 07:30~08:50 나. 장소 : 팔래스호텔 12층 다봉 다. 참석자 : ','포럼 활성화 방안 협의를 위한 간담회를 개최하고 그 결과를 아래와 같이 보고합니다. - 아 래 - 가. 일시 : 2012.11.21.(수) 07:30~08:50 나. 장소 : 팔래스호텔 12층 다봉 다. 참석자 : 석호익 회장 등 8인 라. 주요내용 : 붙임 회의록 참조','2012-11-27','','','',1,20,'2012-11-27 00:00:00','2012-11-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 11/15 정책간담회 개최결과','포럼 활성화 방안 협의를 위한 간담회를 개최하고 그 결과를 아래와 같이 보고합니다. - 아 래 - 가. 일시 : 2012.11.15.(목) 07:30~08:40 나. 장소 : 팔래스호텔 12층 다봉 다. 참석자 : ','포럼 활성화 방안 협의를 위한 간담회를 개최하고 그 결과를 아래와 같이 보고합니다. - 아 래 - 가. 일시 : 2012.11.15.(목) 07:30~08:40 나. 장소 : 팔래스호텔 12층 다봉 다. 참석자 : 석호익 회장 등 9인 라. 주요내용 : 붙임 회의록 참조','2012-11-27','','','',1,19,'2012-11-27 00:00:00','2012-11-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 조찬간담회 겸 임시총회 개최결과','1. 그간 안녕하십니까? 포럼 발전을 위하여 항상 많은 관심을 가지시고 지원 해 주심을 감사드립니다. 2. 정관 제 16조의 규정에 의거 포럼 활성화를 위한 정관개정과 내년도 신정부 출범에 따른 통일정책방향 변화에 ','1. 그간 안녕하십니까? 포럼 발전을 위하여 항상 많은 관심을 가지시고 지원 해 주심을 감사드립니다. 2. 정관 제 16조의 규정에 의거 포럼 활성화를 위한 정관개정과 내년도 신정부 출범에 따른 통일정책방향 변화에 대비한 포럼 활성화 방안 협의를 위하여 임시 총회를 겸한 조찬간담회를 개최하고, 그 결과를 아래와 같이 보고합니다. - 아 래 - 가. 일 시 : 2012.9.13.(목) 07:30~09:30 나. 장 소 : 리버사이드 호텔 7층 파크홀 (잠원동 소재) 다. 참석대상 : 포럼 회장, 부회장, 이사 및 회원 59명 라. 행사순서 [ 제1부 : 초청강연 ] 07:30 ~ 09:00 · 행사안내 : 사회자 · 인사말씀 및 주요 내빈소개 : 석호익 회장 · 초청강연 – 통일환경과 우리의 과제 : 조명철 국회의원 [ 제2부 : 임시총회 ] 09:00 ~ 09:30 · 정관개정(안) 승인의 건 - 6/22 이사회 의결사항 - 법인의 주사무소의 소재지 변경 : 과천시 → 서울특별시 - 임원 수 변경 : 이사 30명 이내 → 이사 30명이내 (회장포함) (회장,부회장 15인 포함) - 시행일 : 주무관청의 허가를 받은 날부터 시행','2012-11-27','','','',1,18,'2012-11-27 00:00:00','2012-11-27 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','"전국 ICT포럼" 행사에 초청합니다.','안녕하세요. 통일IT포럼 사무국입니다. 통일IT포럼에서는11월 23일 금요일, 하림각(AW컨벤션센터)에서 개최예정인 "전국 ICT 포럼"에 회원분들을 초청합니다. 통일IT포럼 회원 전용 테이블이 별도로 마련되어 있사','안녕하세요. 통일IT포럼 사무국입니다. 통일IT포럼에서는11월 23일 금요일, 하림각(AW컨벤션센터)에서 개최예정인 "전국 ICT 포럼"에 회원분들을 초청합니다. 통일IT포럼 회원 전용 테이블이 별도로 마련되어 있사오니, 참가를 원하시는 분께서는 ICT포럼 사무처에 참가신청하시기 바랍니다. 감사합니다.','2012-11-16','','','',1,17,'2012-11-16 00:00:00','2012-11-16 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[통일IT포럼] 조찬간담회 겸 임시총회 참석요청','[통일IT포럼] 조찬간담회 겸 임시총회 참석요청','[통일IT포럼] 조찬간담회 겸 임시총회 참석요청','2012-08-24','','','',1,16,'2012-08-24 00:00:00','2012-08-24 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','HSN2012(2012.1.11-13, 제주그랜드호텔) 행사 안내','HSN 2012 (The 22 nd High-Speed Network Workshop) "Human-Centric Networking for The Future" www.hsn.or.kr 1. 행사개요 [ 행사명 ]','HSN 2012 (The 22 nd High-Speed Network Workshop) "Human-Centric Networking for The Future" www.hsn.or.kr 1. 행사개요 [ 행사명 ] The 22 nd High-Speed Network Workshop(HSN 2012) [ 일 자 ] 2012. 1. 11( 수 ) ~ 13( 금 ) [ 장 소 ] 제주 그랜드 호텔 ( 약도참조 ) [ 주 관 ] 개방형컴퓨터통신연구회 , 대한전자공학회 , 한국네트워크산업협회 , 한국정보과학회 , 한국정보처리학회 , 한국정보통신설비학회 , 한국통신학회 [ 후 원 ] ㈜다산네트웍스 , ㈜럭스퍼트 , 모다정보통신㈜ , ㈜세종텔레콤 , ㈜엠엠씨테크놀로지 , 중앙네트웍솔루션㈜ , ㈜크래블 , ㈜텔레필드 , ㈜피엠그로우 , CJ 헬로비전 , ㈜ KT, ㈜ KT 네트웍스 , LG-Ericsson ㈜ 2. 등록안내 ※ 사전등록기간 : 2011 년 12 월 5 일 ( 월 ) ~ 12 월 30 일 ( 금 ) 까지 ※ 행사 홈페이지 ( http://www.hsn.or.kr ) 에서 온라인 등록 후 등록비 송금 . - 등록비 ( 입금계좌 : 신한은행 140-004-615360 ( 예금주 : 개방형컴퓨터통신연구회 )) 구 분 등 록 비 ( 숙박비 미포함 ) 일 반 학 생 사전등록 35 만원 15 만원 현장등록 40 만원 20 만원 - 모든 참가자에게 자료집이 제공됩니다 . - 현장 등록자는 계산서 발급을 원할 경우 행사 당일 사업자등록증 사본을 지참해야 합니다 . ( 단 , 신용카드 결제시 계산서는 발행해 드리지 않습니다 .) - 경품 추첨 합니다 . 3. 문의 - 등록 및 행사문의 : 개방형컴퓨터통신연구회 Tel. 02-562-7041~2, e-mail. workshop@osia.or.kr - 숙박 / 항공 / 렌트 문의 : 제주 그랜드호텔 서울지점 박슬기 Tel. 02-2278-2100, e-mail. oraseoul@oraresort.com - HSN 2012 웹사이트 : www.hsn.or.kr - 개방형컴퓨터통신연구회 웹사이트 : www.osia.or.kr 4. 프로그램 1 일차 1 월 11 일 ( 수 ) 시간 내용 좌장 / 발표자 12:00-13:00 등록 Session 1: Big Data 좌장 : 하상용 부장 /NIA 13:00-13:30 Big Data, Big Analytics – Data Science 로 가는 길 이진권 상무 /SAS Korea 13:30-14:00 빅데이타를 활용한 스마트 정부 김현곤 단장 /NIA 14:00-14:15 휴식 Session 2: 네트워크 발전전략 좌장 : 김대식 소장 /ETRI 14:15-14:35 모바일 광개토 플랜 추진을 위한 주파수 정책 방향 김정삼 과장 / 방송통신위원회 14:35-14:55 미래를 대비한 인터넷 발전전략 김정렬 과장 / 방송통신위원회 14:55-15:15 차세대 통신 네트워크 육성 전략 최우석 과장 / 지식경제부 15:15-15:30 휴식 Plenary Session 15:30-15:40 개회사 정일영 운영위원장 / 한국외대 부총장 15:40-15:50 환영사 TBD 15:50-16:00 축사 TBD Session 3: 통신사업자의 네트워크 개발 및 진화 전략 좌장 : 이상홍 부원장 /KT 16:00-16:30 KT 의 차세대 네트웍 진화 전략 이경수 본부장 /KT 16:30-17:00 SK 텔레콤 Network 고도화 방안 이종봉 본부장 /SKT 17:00-17:30 Special Session : HSN 22 년과 우리나라 IT 발전 강철희 교수 / 고려대 17:30-19:00 석식 Panel Session 좌장 : 홍진표 교수 / 한국외대 19:00-21:30 인터넷 생태계와 망중립성 2 일차 1 월 12 일 ( 목 ) 시간 내용 좌장 / 발표자 Session 4: Mobile Platform and Cloud 좌장 : 이영로 표준코디네이터 / 지경부 기표원 09:00-09:30 Mobile Platform Outlook TBD 09:30-10:00 오픈소스기반 클라우드 인프라 기술 현황 및 진화방향 안재석 박사 /KT 10:00-10:30 SaaS 플랫폼 및 페타스케일 클라우드 스토리지 기술동향 최완 부장 /ETRI 10:30-10:50 휴식 Session 5: Wireless Capacity and Connectivity 좌장 : 전경표 박사 /ETRI 10:50-11:20 LTE/LTE-Advanced and The Next 방승찬 부장 /ETRI 11:20-11:50 WiFi vs. Femtocell 최성현 교수 / 서울대 11:50-12:20 모바일 광대역 기술의 진화 : LTE-A 와 HetNet 권경인 상무 /LG 에릭슨 12:20-13:30 중식 Session 6: Paradigm Shift in Networking 좌장 : 김종권 교수 / 서울대 13:30-14:00 ID based Networking On Autonomous Domains 전우직 박사 /ETRI 14:00-14:30 Secure Personal Content Networking over Untrusted Devices 이의진 교수 /KAIST 14:30-15:00 Topology and Scale Free Networks for Future Internet 한상언 교수 / 전북대 15:00-15:20 휴식 Session 7: Dynamic Spectrum Sharing 좌장 : 김대영 교수 / 충남대 15:20-15:50 Current status of TV white space service in UK Dr. Maziar Nekovee/BT Research 15:50-16:20 공학적인 측면에서 본 Spectrum deregulation 방안의 제안 김정호 교수 / 이화여대 16:20-16:50 Spectrum (trading and) deregulation in Korea 이홍재 교수 / 아주대 16:50-17:10 휴식 Keynote Speech Session 좌장 : 정 송 교수 /KAIST 17:10-18:00 TBD 양승택 전 정보통신부 장관 18:30-20:30 Banquet 3 일차 1 월 13 일 ( 금 ) 시간 내용 좌장 / 발표자 Session 8: M2M 좌장 : 이형호 박사 /ETRI 09:00-09:25 Globally Standardized M2M 단말 플랫폼 김용진 부사장 / 모다정보통신 09:25-09:50 SKT M2M 단말 표준 플랫폼 개발 현황 및 계획 한창문 팀장 /SKT 09:50-10:15 KT M2M 기반 융합 서비스 기술 허성필 팀장 /KT 10:15-10:40 M2M 플랫폼 기반 서비스 기술 및 현황 최성우 차장 /LG U+ 10:40-11:00 휴식 Session 9: Network Security 좌장 : 성단근 교수 /KAIST 11:00-11:30 최근 사이버 공격 동향 및 방어 기술 차영균 상무 / 시큐아이닷컴 11:30-12:00 전력 인프라 ( 스마트그리드 ) 공격 위협 및 방어 전략 최동근 이사 / 롯데정보통신 12:00-12:30 모바일 클라우드 서비스의 보안 위협 및 대응방안 김형종 교수 / 서울여대 * 프로그램은 사정상 변경될 수 있습니다 .','2011-12-29','','','',1,15,'2011-12-29 00:00:00','2011-12-29 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2011년 통일IT포럼 송년회 참석요청','안녕하십니까? 통일IT포럼 발전을 위하여 항상 많은 관심을 가지고 참여하여 주심을 감사드립니다. 2011년도 통일IT포럼 행사를 아래와 같이 개최하고자 하오니, 많은 참석부탁드립니다. 식사인원 파악 등 행사준비에 꼭','안녕하십니까? 통일IT포럼 발전을 위하여 항상 많은 관심을 가지고 참여하여 주심을 감사드립니다. 2011년도 통일IT포럼 행사를 아래와 같이 개최하고자 하오니, 많은 참석부탁드립니다. 식사인원 파악 등 행사준비에 꼭 필요하오니 2011.12.12(월)까지 참석여부를 알려주시면감사하겠습니다. - 아 래 - 가. 일 시 : 2011년 12월 19일(월) 18:30~21:00 나. 장 소 : 프레지던트 호텔 19층 브람스홀 (서울 중구 을지로1가 188-3) 다. 참석대상 : 회원 전원 및 초청인사 (부부동반 참석 가능) 라. 행사순서 [ 제1부 : 송년 특별강연 ] 18:30 ~ 19:20 · 포럼현황 및 행사안내 : 사회자 · 인사말씀 및 주요내빈소개 : 석호익 회장 · 특별강연 - 북한방송통신기술 및 표준화동향 연구 : 최성 교수 (남서울대학교) - 통일준비와 통일 교육의 과제: 조명철 원장 (통일교육원) [ 제2부 : 만찬 ] 19:20 ~ 19:50 · 건배제의 · 만 찬 : 참석자소개, 자율회비(기부금) 내역소개 [ 제3부 : 문화공연 ] 19:50 ~ 20:30 · 평양민속공연단 마. 참가비 : 없음. 단, 자율적인 회비(기부금) 납부는 가능 바. 참석여부 통보 및 행사문의 : 윤노을 연구원 ( 070-8233-3420/noeul@kani.or.kr )','2011-12-02','','','',1,14,'2011-12-02 00:00:00','2011-12-02 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 `11.07.15. 조찬간담회 행사사진.','통일IT포럼 `11.07.15. 조찬간담회 행사사진.','통일IT포럼 `11.07.15. 조찬간담회 행사사진.','2011-07-25','','','',1,13,'2011-07-25 00:00:00','2011-07-25 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','[행사] 통일IT포럼 조찬간담회 참석요청','통일IT포럼 조찬간담회를 아래와 같이 개최하오니 회원 여러분의 많은 참석을 부탁드립니다. - 아 래 - 1. 개최 일시 : 2011.07.15.(금) 07:30 ~ 09:10 2. 개최 장소 : 서울 프라자 호텔 4','통일IT포럼 조찬간담회를 아래와 같이 개최하오니 회원 여러분의 많은 참석을 부탁드립니다. - 아 래 - 1. 개최 일시 : 2011.07.15.(금) 07:30 ~ 09:10 2. 개최 장소 : 서울 프라자 호텔 4층 메이플 홀(지하철 2호선 시청역 6번 출구) 3. 발표자 및 제목 : 포원비즈 김병수 대표 북한 IT 인력 활용 현황(포원비즈 실제 사례 중심) 4. 행사순서 - 07:30 ~ 08:10 참석자 상호간 인사 및 조찬 - 08:10 ~ 08:15 회장님 인사말씀 - 08:15 ~ 08:20 축사(선진통일 연합 박세일 상임의장 예정) - 08:20 ~ 09:00 발표자 발표 및 질의응답 - 09:00 ~ 09:10 포럼 소개 및 공지사항 5. 참가 신청방법 : 이메일 또는 전화신청(마감기한 : 7월8일 금요일) (윤노을 연구원 noeul@knra.or.kr , 070-8233-3420) 6. 찾아오시는 길 : 호텔 홈페이지 참조( https://www.hoteltheplaza.com/kor/location/location.jsp )','2011-06-24','','','',1,12,'2011-06-24 00:00:00','2011-06-24 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','KANI 솔루션 페어 2011 행사에 초대합니다.','KANI 솔루션 페어 2011 행사에 초대합니다.','KANI 솔루션 페어 2011 행사에 초대합니다.','2011-06-08','','','',1,11,'2011-06-08 00:00:00','2011-06-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','"북한 이동통신 시장 현황과 투자기회" 국제포럼 참석요청','조선비즈 국제 콘퍼런스 북한 통신산업 및 시장을 전망하는 최초의 국제 포럼이 서울에서 열립니다. 최근 이집트 모바일 혁명을 계기로 북한 사회에 급속히 퍼지고 있는 휴대전화(2년 만에 30만대)의 현황에 대한 관심이 ','조선비즈 국제 콘퍼런스 북한 통신산업 및 시장을 전망하는 최초의 국제 포럼이 서울에서 열립니다. 최근 이집트 모바일 혁명을 계기로 북한 사회에 급속히 퍼지고 있는 휴대전화(2년 만에 30만대)의 현황에 대한 관심이 고조되고 있습니다. 조선미디어 그룹의 경제투자 매체 조선비즈(www.chosunbiz.com)는 영국, 독일, 중국 등 국내외 최고의 통신 및 북한 전문가들을 모시고 ‘북한 이동통신 시장 현황과 투자 기회’라는 주제로 국제 포럼을 개최합니다. 세계적인 통신시장 분석기관 오범(Ovum)의 엔젤 도바르드지에브(Dobardziev) 글로벌 대표는 북한에서 휴대전화 서비스를 제공하는 이집트 오라스콤텔레콤의 북한 진출 전략을 분석하고 , 전(前) 중국통신협회 회장을 역임한 중국 통신 컨설팅 회사 이관궈지(易觀國際) 위양(于揚) 대표는 중국 내부 분석 자료를 바탕으로 북한 통신 현황과 전망을 제시합니다. 독일의 한스자이델재단 베른하르트 젤리거 박사, 김흥광 북한지식연대 대표, 오중석 자유아시아방송(RFA) 서울지국장은 폐쇄와 단절의 국가 북한에서 불고 있는 휴대전화 열풍과 그 사회적 파장을 진단합니다. 송태수 한국기술교육대 교수, 양문수 북한대학원대학교 교수 등 국내에서 손꼽히는 북한 경제학자들의 발표와 심도 있는 토론도 준비돼 있습니다. 이번 포럼은 북한 이동통신 시장의 현재와 미래를 짚어보는 최초 국제 포럼입니다. 북한의 경제적, 산업적 투자 기회를 한발 앞서 알아보고 더 나아가 북한의 사회 변화의 역동성도 짚어보는 유익한 자리가 될 것입니다. 이번 포럼에서는 북한 관련 포럼과 전문가를 소개하고 서로 네트워킹할 수 있는 자리를 충분히 가질 예정입니다. 통일 시대를 준비하고 뉴미디어가 사회에 미치는 영향에 관심이 많은 분들의 많은 참여바랍니다. <북한 이동통신 포스터> ◆ 주제 : 북한 이동통신 시장 현황과 투자 기회 3G Penetration trends and Investment Opportunities in North Korea Mobile Infrastructure 관련 영상 클릭! ◆일시 : 2011년 4월 12일(화) 09:00 ~ 14:00 (사전등록자 및 현장등록 오전 8시 30분부터) ◆장소 : 대한상공회의소 의원회의실 (서울 남대문 옆 소재) ◆주최 : 조선비즈 ◆후원 : 통일부, 방송통신위원회, 한국정보화진흥원, 한국방송통신전파진흥원, 통일IT포럼 , 자유아시아방송(RFA), 조선일보사 ◆신청 : 등록·안내 = www.chosunbiz.com (선착순, 참가비 유료) ◆ 참가비: 일반인 11만원(부가세 포함 / 오찬, 자료집(E-paper) 제공) 페이스북 ‘ 북한경제포럼 ’ 그룹에 가입한 후 등록하면 50% 할인(선착순) 등록/안내 바로가기 클릭 ◆문의=사무국(02)724-6075 / help@chosunbiz.com 본 프로그램 4월 12일 사 회 시 간 프로그램 발제자 08:30~09:00 등 록 참가자 등록 09:00~09:10 축 사 현인택 /통일부 장관 석호익 / 통일 IT 포럼 회장 기조연설 09:10~09:40 1st Keynote Speech 오라스콤의 북한 모바일 시장 진출 전략과 모바일이 아시아, 아프리카, 중동에 미친 영향 앤젤 도바르지에브(Dobardziev)/ 영국 오범(Ovum) 글로벌 대표 (Global Head) 신흥 통신 시장(Emerging Market Telecom) 연구 총괄 09:40~09:55 질의응답 SESSION 1 북한 통신 인프라 투자 기회 탐구 09:55~10:15 주제 발표 중국이동통신 발전전략을 통해 본 시사점 Chinese Mobile Communications Development Strategies and Their Implications 위양(于揚) / 이관궈지 (易觀國際) 대표 전(前) 중국통신협회 회장 10:15~10:30 주제 발표 동서독 통일과정이 북한 통신 분야 투자에 주는 교훈 송태수 / 한국기술교육대학 교수 10:30~10:45 주제 발표 북한 통신 인프라 현황 및 전망 황성진 /정보통신정책연구원 북한방송통신연구센터장 10:45~10:55 Coffee Break Coffee Break SESSION 2 뉴미디어의 등장과 북한의 경제 사회적 변화 10:55~11:10 주제 발표 조용하지만은 않은 혁명 - 북한의 휴대전화, 수평적 커뮤니케이션 그리고 사회적 변화 A (not so) quiet revolution – cell phones, horizontal communication and societal change in North Korea 베른하르트 젤리거 / 한스자이델재단 서울사무소대표 11:10~11:25 주제 발표 북한 사회내의 미디어 유포 및 활용 실태 – 뉴미디어를 중심으로 김흥광 / NK지식인연대 대표 11:25~11:40 주제 발표 북한 뉴스 보도와 북한의 이동통신 오중석 / 자유아시아방송(RFA) 서울지국장 11:40~12:00 종합토론 Q&A 토론 주제 1 북한 통신 인프라 투자 기회 토론 주제 2 뉴미디어의 등장과 북한사회의 변화 양문수 / 북한대학원대학교 교수 김유향 / 국회입법 조사처 문화통신팀장 김상배 / 서울대 정치외교학부 교수 12:00~14:00 오 찬 단체, 대학 및 포럼 소개 * 행사 프로그램은 사정에 따라 변경될 수 있습니다. 약 도 : 서울특별시 중구 남대문로 4가 45번지 대한상공회의소 지하 2층 의원회의실 *','2011-04-07','','','',1,10,'2011-04-07 00:00:00','2011-04-07 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 2010년 송년회 참석 요청','금년도 본 포럼에서 수행한 남북한 방송통신표준 연구내용을 발표하고 참석자 상호 교류를 통한 포럼 활성화를 위하여, 2010년도 통일IT포럼 송년회를 아래와 같이 개최 하오니 적극 참석하여 주시기 바랍니다. ( 부부동','금년도 본 포럼에서 수행한 남북한 방송통신표준 연구내용을 발표하고 참석자 상호 교류를 통한 포럼 활성화를 위하여, 2010년도 통일IT포럼 송년회를 아래와 같이 개최 하오니 적극 참석하여 주시기 바랍니다. ( 부부동반 가능) 가. 일 시 : 2010년 12월 23일(목) 18:30~20:30 나. 장 소 : 프레지던트 호텔 31층 슈벨트홀 (서울 중구 을지로1가 188-3) 시청역 5번 출구 이용 다. 참석대상 : 회원 전원 및 초청인사 (부부동반 참석 가능) 라. 행사순서 [ 제1부 : 송년 특별강연 ] 18:30 ~ 19:00 · 포럼현황 및 행사안내 : 사회자 · 인사말씀 및 연사 소개 : 석호익 회장 · 특별강연 - 남북한방송통신표준 : 최성 교수 (남서울대 학교) [ 제2부 : 만찬 ] 19:00 ~ 19:30 · 건배제의 · 만 찬 : 참석자소개, 자율회비(기부금) 내역 소개 [ 제3부 : 문화공연 ] 19:30 ~ 20:30 · 가수 이은하 공연 마. 참가비 : 없음 단, 자율적인 회비(기부금) 납부는 가능 바. 참석여부 통보 및 행사문의 : 전미진 연구원 ( 070-8233-3420/littledog85@knra.or.kr ) 찾아오시는길 : 호텔 홈페이지 참조 ( http://www.hotelpresident.co.kr/korean/ )','2010-12-07','','','',1,9,'2010-12-07 00:00:00','2010-12-07 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2009년도 제1회 임시총회 및 송년회 개최 결과','2009년 12월 29일에 개최한 2009년도 제1회 임시총회 및 송년회 결과를 아래와 같이 알려드립니다. 1. 일 시 : 2009년 12월 29일(화) 18:30 ~ 21:00 2. 장 소 : 서울 프라자 호텔 4','2009년 12월 29일에 개최한 2009년도 제1회 임시총회 및 송년회 결과를 아래와 같이 알려드립니다. 1. 일 시 : 2009년 12월 29일(화) 18:30 ~ 21:00 2. 장 소 : 서울 프라자 호텔 4층 메이플룸 3. 참 석 자 : 통일IT포럼 석호익 회장 등 53명 4. 행 사 순 서 및 결 과 [ 제 1부 : 임시총회 ] 18:50 ~ 19:10 □ 임원선임의 건 : 2009년 11월 18일 이사회에서 의결한 임원 추천(안)을 원안 의결함 □ 주요내용 ○ 회장 (1인) : KT 석 호 익 부회장 ○ 부회장 (8인) : 삼성전자 김운섭 부사장, KT 김영환 부사장, SKT 이형희 전무, 유니코텍코리아 유완영 회장, 다산네트웍스 이상산 부사장, 넷피아 이판정 사장, 비트컴퓨터 조현정 회장, 한국네트워크연구조합 구교광 사무국장, ○ 이사 (11인) : 미래재단 구해우 상임이사, 한국학중앙연구원 김현 한국학정보센터장, 삼성경제연구소 동용승 경제보안팀장, KT 서종렬 본부장, 통일문제연구원협의회 손기웅 사무국장, 한국과학기술정책연구원 이춘근 남북협력팀장, 한국과학기술정보연구원 최현규팀장, 남북경제협력진흥원 임완근 원장, 한국기술사협회 문행규 회장, 남서울대학교 최성 교수, 전자신문 김상용 부장 ○ 감사 (1인) : 전자신문 신화수 부국장 [ 제 2부 : 송년 특별강연 및 만찬 ] 19:10 ~ 20:30 □ 인 사 말 - 통일IT포럼 석호익 회장 □ 특별강연 - 북한의 방송통신 현황과 지원 방안 : 김흥광 (사) NK지식인 연대 대표 (전 함흥공산대학 과학연구부 교수) (발표자료 : 통일IT포럼 자료실 참고) □ 만 찬 [ 제 3부 : 문화공연 ] 20:30 ~ 21:00 □ Papera Group DID','2010-01-05','','','',1,8,'2010-01-05 00:00:00','2010-01-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2009년도 통일IT포럼 이사회 개최 안내','2009년도 통일IT포럼 이사회가 아래와 같이 개최 될 예정이오니, 관련있는 분들은 참석하여 주시기를 바랍니다. - 아 래 - 1. 일 시 : 2009년 11월 18일(수) 08:00 ~ 09:00 2. 장 소 : ','2009년도 통일IT포럼 이사회가 아래와 같이 개최 될 예정이오니, 관련있는 분들은 참석하여 주시기를 바랍니다. - 아 래 - 1. 일 시 : 2009년 11월 18일(수) 08:00 ~ 09:00 2. 장 소 : 서울 프레지던트 호텔 18층 동해 식당 3. 상정안건 : 가. 임원 (회장, 부회장, 이사)의 선임과 해임안 나. 기타 통일IT포럼 활성화 방안 4. 참석대상자 □ 회장 (1인) : 석 호 익 회장 □ 부회장 (13인) : 삼성전자 김운섭 부사장, KT 김영환 사장, SKT 이형희 상무, SK브로드밴드 박종훈 전무, 서승모 C&S Technology 대표이사, 유니코텍코리아 유완영 회장, 다산네트웍스 이상산 부사장, 넷피아 이판정 사장, 비트컴퓨터 조현정 회장, 한국네트워크연구조합 구교광 사무국장, 큐브리트 강태헌 대표 □ 이사 (12인) : 미래재단 구해우 상임이사, 한국학중앙연구원 김현 센터장, 삼성경제연구소 동용승 경제보안팀장, 하나비즈닷컴 문광승 대표, 비즈텔런트 서종렬 사장, 통일문제연구원협의회 손기웅 사무국장 , 한국과학기술정 책연구원 이춘근 팀장, 한국과학기술정보연구원 최현규 팀장, 남북경제협력진흥원 임완근 원장, 한국기 술사협회 문행규 회장, 남서울대학교 최성 교수, 전자신문 서현진 부국장 □ 감사 (1인) : 전자신문 장길수 팀장','2009-11-09','','통일IT포럼 임시총회기안.pdf [123KB]','',1,7,'2009-11-09 00:00:00','2009-11-09 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','연변조선족자치주정보산업협회와 IT아웃소싱센터 공동구축에 관한 의견수렴','IT 분야에서 글로벌협업체제는 국가경쟁력의 중요한 요소가 되었습니다 . 미국은 인도를 , 일본은 중국 대련을 아웃소싱센터로 개발 육성하여 경쟁력강화를 도모하고 있습니다 . 세계 최강의 우리나라 IT 분야도 이제 질적','IT 분야에서 글로벌협업체제는 국가경쟁력의 중요한 요소가 되었습니다 . 미국은 인도를 , 일본은 중국 대련을 아웃소싱센터로 개발 육성하여 경쟁력강화를 도모하고 있습니다 . 세계 최강의 우리나라 IT 분야도 이제 질적 , 양적 측면에서 심한 인력난에 봉착하고 있어 , 범 국가적 차원에서 글로벌 협력체제를 구축하여 개별 기업들 의 경쟁력 향상을 지원할 필요가 있다고 생각합니다 . 이에 통일 IT 포럼에서는 연변조선족자치주정보산업협회와 협력하여 우리나라의 IT 아웃 소싱센터를 중국연변에 구축하는 프로젝트에 대해 구체적인 시장조사를 실시하고 있습니다 . 연변 IT 아웃소싱센터 ( 소프트웨어개발 , 콜센터 등 ) 에 대해 투자 등 사업추진에 관심 있으신 분들은 좋은 의견을 주시면 고맙겠습니다 .( 첨부물 참조 ) ( 문의 : 통일 IT 포럼 상임이사 문행규 016-9720-9720, hkmoon123@naver.com)','2008-01-03','','국제IT개발펀드설립080103v2.doc [44KB]','',1,6,'2008-01-03 00:00:00','2008-01-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 월례 조찬회 개최빈도 설문조사중입니다.','안녕하세요. 통일IT포럼 사무국입니다. 통일IT포럼 월례 조찬회 개최빈도 문의 설문조사의 많은 참여 부탁드립니다. 게시판 -> 설문조사를 통해 회원님들의 많은 의견 부탁드립니다. 감사합니다. 통일IT포럼 사무국 02','안녕하세요. 통일IT포럼 사무국입니다. 통일IT포럼 월례 조찬회 개최빈도 문의 설문조사의 많은 참여 부탁드립니다. 게시판 -> 설문조사를 통해 회원님들의 많은 의견 부탁드립니다. 감사합니다. 통일IT포럼 사무국 02-570-4026','2008-01-03','','','',1,5,'2008-01-03 00:00:00','2008-01-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','2007 동아시아IT포럼','o 행사명 : 2007 동아시아IT포럼 o 일 시 : 2007년 11월26일(월) ~ 12월 1일(토), 5박 6일 o 장 소 : 중국 길림성 연변조선족 자치주 연길시 국제호텔 o 주 관 : 통일IT포럼, 조선민족과','o 행사명 : 2007 동아시아IT포럼 o 일 시 : 2007년 11월26일(월) ~ 12월 1일(토), 5박 6일 o 장 소 : 중국 길림성 연변조선족 자치주 연길시 국제호텔 o 주 관 : 통일IT포럼, 조선민족과학기술협회, 중국중문신식학회 o 주 최 : 정보통신국제협력진흥원, 전자신문사 o 후 원 : KT, SKT, 다산네트웍스','2007-11-19','','','',1,4,'2007-11-19 00:00:00','2007-11-19 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','정회원 가입안내','정회원 이란? 개인/기업회원 가입안내를 참고하시가 바랍니다. 연회비를 납부한 회원으로써 e-멤버스 가입신청후 사무국으로 연락주시가 바랍니다. 통일IT포럼 회원활동과 다양한 해택을 받으실 수 있습니다. 받으실 수 있습','정회원 이란? 개인/기업회원 가입안내를 참고하시가 바랍니다. 연회비를 납부한 회원으로써 e-멤버스 가입신청후 사무국으로 연락주시가 바랍니다. 통일IT포럼 회원활동과 다양한 해택을 받으실 수 있습니다. 받으실 수 있습니다.','2007-10-08','','','',1,3,'2007-10-08 00:00:00','2007-10-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','e-멤버스회원 가입안내','e-멤버스회원 이란? 통일IT포럼 홈페이지 가입하여, 여러가지 정보를 얻고, 자유게시판 등 글을 남길 수 있는 회원 입니다. 가입안내에서 약관에 동의체크를 하시고 회원정보를 입력해 주시기 바랍니다.','e-멤버스회원 이란? 통일IT포럼 홈페이지 가입하여, 여러가지 정보를 얻고, 자유게시판 등 글을 남길 수 있는 회원 입니다. 가입안내에서 약관에 동의체크를 하시고 회원정보를 입력해 주시기 바랍니다.','2007-10-08','','','',1,2,'2007-10-08 00:00:00','2007-10-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('notice','통일IT포럼 향후 주요 일정 공지','통일IT포럼 향후 주요 일정을 공지하오니 참고하여 주시기 바랍니다. 일시 장소 행사명 11. 15(목)~18(일) (추진중) 중국연길 국제호텔 ‘남․북․중 IT 공동세미나’개최 12. 13(목) 18:30~21:00','통일IT포럼 향후 주요 일정을 공지하오니 참고하여 주시기 바랍니다. 일시 장소 행사명 11. 15(목)~18(일) (추진중) 중국연길 국제호텔 ‘남․북․중 IT 공동세미나’개최 12. 13(목) 18:30~21:00 전경련회관 경제인클럽 2007 통일IT포럼 송년회 - 1부 : 2007년 통일IT포럼 사업성과보고 및 결산 - 2부 : 송년만찬 및 문화행사(공연)* 2008. 1. 9(수)07:30~09:00 웨스틴조선호텔 제5차 조찬토론회 - 특별강연 : 남중수 KT사장 * 문화행사(공연)과 관련하여 좋은 의견이 있으신 분들은 사무국으로 연락주시기 바랍니다. 감사합니다. 담당자: 통일IT포럼 사무국 최현주 ☎ 02)570-4026 e-mail : hjchoi@kisdi.re.kr','2007-09-20','','','',1,1,'2007-09-20 00:00:00','2007-09-20 00:00:00');
