INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제82차 조찬간담회 발표자료 (23.07.04)','제82차 조찬간담회에서 이화여대 박원곤 교수님이 발표하신 "급변하는 국제정세와 한반도" 발표자료(2023.07.04)를 첨부하오니 필요하신 분은 아래 첨부에서 다운로드 받으시기 바랍니다.','제82차 조찬간담회에서 이화여대 박원곤 교수님이 발표하신 "급변하는 국제정세와 한반도" 발표자료(2023.07.04)를 첨부하오니 필요하신 분은 아래 첨부에서 다운로드 받으시기 바랍니다.','2023-07-05','','국제정세와한반도(2023.6.20).pptx [4042KB]','',1,85,'2023-07-05 00:00:00','2023-07-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','2023년 통일부 주요업무 추진계획','2023년 주요업무 추진계획 2023. 1. 27. 통일부 순 서 Ⅰ. 추진성과와 평가 1 Ⅱ. 2023년 업무추진 여건 및 방향 3 Ⅲ. 2023년 부처 핵심 추진과제 5 I. 추진성과와 평가 1 주요 정책 성과 ','2023년 주요업무 추진계획 2023. 1. 27. 통일부 순 서 Ⅰ. 추진성과와 평가 1 Ⅱ. 2023년 업무추진 여건 및 방향 3 Ⅲ. 2023년 부처 핵심 추진과제 5 I. 추진성과와 평가 1 주요 정책 성과 □ ｢담대한 구상｣을 마련하고 국내외 협력 추진 ㅇ 광복절 계기 북한 핵문제 해결의 포괄적 구상 제시 - 북한 비핵화 조치와 경제·정치·군사적 상응 조치의 동시적·단계적 이행 방안 마련(관계부처 합동) ㅇ ｢담대한 구상｣의 공감대 확산 - 통일‧대북정책 설명자료 국내외 주요기관 배포(12월, 1만 3천여부) - ｢담대한 구상｣ 이행을 위한 공개 세미나, 주한 외교단 정책설명회 개최 □ 일관된 원칙을 바탕으로 남북관계 재정립 추진 ㅇ 북한의 도발과 잘못된 언행에 단호히 대처 - 금강산·개성공단 재산침해 중단 촉구 등 20여회 통일부 입장 발표 ㅇ 윤석열 정부의 통일‧대북정책 마련, 정책 ‘이어달리기’ 추진 - 비핵‧평화‧번영의 한반도를 위한 3대 원칙, 5대 추진과제 구체화 * (3대 원칙) ①일체의 무력도발 불용 ②호혜적 남북관계 발전 ③평화적 통일기반 구축 * (5대 추진과제) ①비핵화-남북 신뢰구축 선순환 ②상호 존중에 기반한 남북관계 정상화 ③북한 주민 인권 증진과 분단 고통 해소 ④개방과 소통을 통한 민족동질성 회복 ⑤국민‧국제사회와 함께하는 통일준비 - 인도지원과 남북대화에 대한 일관된 입장 견지, 대북 방역협력‧이산가족 회담 제안 등 대북통지문 전달 7회 시도 ㅇ 자유‧인권‧법치 등 보편가치에 부합하지 않은 정책‧입장을 정상화 - △｢남북관계발전법｣ 대북전단금지 관련 조항 위헌 △공무원 서해 피격 사건 대응 관련 입장 등 표명 - ｢북한이탈주민법｣ 개정안 입법예고(12.7~1.16), 통일부 장관이 북한 주민 탈북의사 확인 □ 북한인권 증진 노력 본격화 ㅇ 북한인권을 국정운영 최우선 의제 중 하나로 제시 - ｢북한인권정책협의회｣ 재개 및 ｢북한인권증진계획｣ 수립 등 정부 차원의 진정성 있는 대책 마련 ㅇ 북한인권 관련 국내외 협력 추진 - △5년만에 통일부 주관 ‘북한인권 민관합동 워크숍’ 개최(10.31) △‘2022 북한인권 국제대화’ 개최(12.14) 등 2 개선 필요사항 ㅇ 북한은 핵개발을 지속하며 남북간 대화를 거부 - 전술핵무기 다량 생산‧핵탄두 보유량 확대 추진 등 ㅇ ‘북한인권재단’이 출범하지 못하는 상황이 장기화 - ｢북한인권법｣의 내실있는 이행에 한계 ㅇ 탈북민 정착지원제도 재설계 필요 - 고독사 방지 등 탈북민의 복합적·다층적 위기상황을 고려하여 특화된 위기관리체계 구축 시급 ⇒ 국민들이 가시적 성과를 체감하기에는 아직 미흡한 것이 현실 Ⅱ. 2023년 업무 추진 여건 및 방향 1 업무 추진 여건 □ (국제) 미중 전략경쟁 속에서 국제질서 불안정성이 중가 ㅇ 미‧중 전략경쟁 지속 - 팬데믹‧기후변화 등 새로운 안보위협도 부상 ㅇ 북·중·러 밀착 강화 □ (북한) 강대강 노선을 견지하면서 ‘잘못된 길’을 고집 ㅇ 민생 외면, 핵‧미사일 등 대량살상무기 개발 * 北, △‘22년 식량작물 생산량은 전년 대비 18만 톤 감소(451만 톤) △‘20년 이후 연속 (-)경제 성장(-4.5%→–0.1%) * 전원회의(’22.12.26~31)시 △새로운 ICBM 개발 △ICBM 정상각도 발사 △전술핵무기 다량 생산 △핵탄 보유량 기하급수적 증대 △군사정찰위성 개발 등 예고 ㅇ 국지도발, 막말비난 등 적대적 태도 지속 - ’22년 역대 최다 미사일 발사(70여발), 김정은이 직접 남북관계를 ‘대적관계’로 규정하며 선제공격 위협 ✔ 지금 우리를 둘러싼 정책 환경은 상당히 어렵고 엄중 ✔ 그러나 ’23년은 우호적 환경을 조성하고, 정책적 공간을 확보하기 위한 적극적 타개 노력이 어느 때보다도 절실한 시점 2 업무 추진 방향 《 2023년 통일부 업무 추진 체계도 》 기본 방향 󰊱 흔들림없는 대북정책 기조 견지 󰊲 국민이 체감하고 공감하는 정책을 만들고 추진 󰊳 국제사회와의 협력연대를 통한 추진동력 확충 7대 핵심추진과제 【올바른 남북관계 구현】 󰊱 담대한 구상 이행 본격화 󰊲 남북관계 정상화 추진 󰊳 북한 주민의 인권 향상 【통일미래 준비】 󰊴 통일미래 청사진, 추진전략 재정립 󰊵 수요자 중심으로 탈북민 지원체계 정비 󰊶 올바른 통일관‧대북관 정립 󰊷 대내외 통일 역량 및 기반 강화 ☞ ｢담대한 구상｣ 구체화 및 추진여건 확보 ☞ 남북관계 정상화 및 안정적 정세 관리 Ⅲ. 핵심 추진과제 󰊱 담대한 구상 이행 본격화 □ ‘3D(억제‧단념‧대화)’의 총체적 접근 강화 ㅇ 강력한 한미동맹에 기반하여 북한의 도발을 확고히 억제 - 북한 도발시 압도적이고 즉각적으로 대응 ㅇ 북한의 핵포기를 향한 국제사회의 의지 결집 - 북한 불법활동 관련 제재 이행 강화 및 독자제재 추진을 통해 북핵 개발 단념 유도 ㅇ 대화를 위한 노력도 꾸준히 전개 - 북한이 대화로 나올 수밖에 없는 환경을 조성 - 일관된 원칙에 입각, 대화시 북한의 잘못된 행태는 분명히 지적 □ ｢담대한 구상｣의 추동력 제고 ㅇ ｢담대한 구상｣의 분야별 이행계획 구체화, 북한이 비핵화 협상 호응시 즉각 추진토록 준비 - 북한의 관심사안 등 고려, 정치‧군사 및 경제분야 세부 상응조치 마련 - 초기조치, 5대 사업 과제별 이행계획 구체화 - 중장기 호혜적 남북경협을 위한 ｢남북공동경제발전계획｣도 발전 ㅇ ｢담대한 구상｣에 대한 국내외 공감대 확산 - 외교부, 민주평통 등 관계기관과 협조 󰊲 남북관계 정상화 추진 □ 남북대화 돌파구 마련 ㅇ 남북간 접촉면 확대 - 민간의 대북접촉 재개 지원, 국제기구 등을 통한 직‧간접 접촉 모색 ㅇ 역사‧종교‧체육 등 사회문화교류 및 그린데탕트 추진 - 종단 행사·겨레말큰사전 등 순수 사회문화교류 추진 - 자연재난 공동대응, 농업·산림·수자원 등 분야별 협력 방안 모색 ㅇ 대화 재개시, 분단으로 인한 인권 침해 및 고통 해소 우선 협의 - 이산가족‧국군포로‧납북자‧억류자 문제 해결 노력 * △제1회 ‘이산가족의 날’ 기념식(9.27, 예정) 등 이산가족 교류기반 구축 △억류자·납북자 관련 새로운 메시지·상징 사업도 병행 - 이산가족 상봉 재개 대북 촉구 □ 남북간 대화‧협력 체계 정립 ㅇ 체계적인 남북대화 틀 마련 추진 - 분야별 고위급‧실무급 협의 및 이행 체계 구축 노력 ㅇ ‘합의한 것은 이행’하는 구조 정착을 통해 남북간 신뢰 형성 ㅇ 법과 원칙에 따른 교류협력 체계 확립, 지속가능한 교류협력을 위한 제도적 장치 보완 - 불법‧일탈적 교류협력 방지 방안 마련 - 신변안전‧투자자산 보호 방안 등 󰊳 북한 주민의 인권 향상 □ ｢북한인권법｣ 이행 정상화 ㅇ ‘민관협력 플랫폼’으로서의 북한인권재단 출범을 위해 국회와 적극 협력 - 재단설립이 북한인권 개선에 미치는 긍정적 효과‧설득논리 등 개발, 북한인권재단 출범을 위한 대국회 소통 및 협력 배가 ㅇ 북한인권재단의 역할을 정부가 실질적으로 수행 - 북한인권재단 출범 전까지 통일부가 국내외 민간단체가 북한인권 증진 활동을 할 수 있도록 협력‧지원(연간 20억원 규모) - 북한인권재단 준비팀 및 (가칭)‘북한인권재단 준비위원회’ 구성, 북한인권재단 출범 전까지 북한인권 증진 노력을 뒷받침 ㅇ 북한인권 개선을 위한 국내외 연대 강화 - (가칭)‘북한인권 현황 연례보고서’를 통한 북한인권 실태 공유‧확산 - 주요국 정부‧국제기구‧시민사회간 북한인권 협력 증진 * △북한인권조사위원회 출범 10주년 △UN 북한인권결의 20주년 계기 담론 확산 □ 인도적 협력의 일관된 추진 ㅇ 북한 주민의 인도적 상황 개선을 위해 노력 - ''실질적 인권 증진'' 차원에서 적극적으로 방안 모색 ㅇ 시급하고 협력이 가능한 분야부터 추진 - 감염병 대응 필수 의약품 중심으로 보건의료 협력 확대 - 영유아 등 취약계층 지원을 위해 국제기구와 협력 - 북한의 식량난, 재해‧재난시 신속하고 실효적인 협력 추진 󰊴 통일미래 청사진, 추진전략 재정립 □ (가칭)｢新통일미래구상｣ 마련 ㅇ 한반도 평화와 민족 번영을 위한 중장기 구상 제시 - 자유, 인권, 소통, 개방 등 보편적 가치 실현을 통한 자유민주적 평화통일 기반 구축 ㅇ 상반기 중 통일미래기획위원회를 중심으로 국민과 전문가 의견수렴 실시, 연내 발표를 목표로 추진 □ ｢민족공동체통일방안｣ 업그레이드 ㅇ △변화된 국제정세 △남북 역학관계 등을 반영, 시대변화에 맞는 통일방안 준비 - ''24년(민족공동체통일방안 발표 30주년) 확정을 목표로 준비 ㅇ 사회적 통일대화 등을 통해 각계각층의 의견 적극 반영 - 민주평통 등 관계기관 협조 하에 국민적 의견을 충분히 수렴 □ 통일미래 민‧관 협업 플랫폼 구축 ㅇ ｢통일미래기획위원회｣ 신설 - 각계 권위있는 전문가로 구성, 분야별 전략그룹 운영 - 1/4분기 중 첫 회의 개최, 통일미래 비전 논의 착수 ㅇ 정책개발 및 공감대 확산의 중심적 역할 수행 - ｢담대한 구상｣ 등 통일미래 비전에 대한 구체화와 국내외 지지 확보를 위한 활동 추진 󰊵 수요자 중심으로 탈북민 지원체계 정비 □ 탈북민 지원 조직 및 업무 재설계 ㅇ 정착지원 조직 기능 조정 - 수도권 등 접근성이 높은 곳에서 재교육·재출발 지원 수요 부응 ㅇ 하나재단 중심으로 행정서비스 공급체계 일원화 - △지방조직 일원화·광역화 △지자체에 업무위임 실질화 등을 통해 지역 서비스 체감도 제고 - ‘정부24’ 에서 탈북민 원스톱 행정·지원 정보 제공 ㅇ 핵심 기능 중심 업무 개편을 통해 보다 나은 삶 지원 - 하나원 교육과정을 일자리 중심으로 개편 * △1인 1기술 자격 △실습ㆍ현장 중심 △취업 연계성 강화 등 - ‘일자리 성공 패키지(취업·창업·영농) 사업’ 등 일자리 지원 확대 - 무연고 청소년 생활장학금, 가산금 신설 추진 □ 탈북민 고독사 방지를 위한 체계적인 위기관리체계 구축 ㅇ 복지 사각지대 우려 대상자(1,200여명) 상시 직접 관리 - 주요 위기지표 활용 등을 통해 위기 발굴 및 예방적 지원 실시 ㅇ ‘마음건강 지원체계’ 활성화를 통한 트라우마 치료체계 구축 - 하나원(상주 의사) - 하나재단(치유센터) - 전문의료‧상담기관 연계 지원 ㅇ 정서적 버팀목이 되는 탈북민 사회적 관계망 지원 - 상호 소통‧지지‧교류할 수 있는 커뮤니티 활성화 및 지역사회 공동체 역량 강화 󰊶 올바른 통일관‧대북관 정립 □ 자유민주주의 통일교육 강화 ㅇ 헌법적 가치에 기반한 통일교육 추진 - 자유인권, 민주주의‧시장경제 등 보편적 가치와 질서 교육 강화, 통일교육 교재(지침서, 기본교재 등)에도 충실히 반영 ㅇ 탈북민을 통한 북한실상 교육 대폭 확대 - 탈북민 포함 전문강사를 통해 국민들이 북한의 실상을 올바르게 이해하도록 교육 * ‘22년 찾아가는 학교통일교육 : 총 1,126회(164,050명) 강의 실시 - 해외에서도 북한의 실상을 바로 알릴 수 있는 방안 마련 ㅇ 학교·지역거점과 연계한 ‘지역통일교육 생태계’ 구축 - △지역통일교육센터 △통일관 △민간단체 등과 연계프로그램 운영 ㅇ 메타버스 등 디지털 통일교육 플랫폼‧콘텐츠 개발 - 추석 계기 이산가족의 염원을 구현한 ‘고향방문 메타버스’ 구축 □ 통일문화 공감행사 개최 ㅇ 5월 통일교육주간과 각종 통일문화행사 통합 개최, 시너지 유도 - △통일교육주간 프로그램 △통일로가요 결선 △통하나봄 문화행사 등 통일미래세대를 위한 다양한 참여·체험프로그램 동시 진행 ㅇ 청년대화 프로그램 등 평화통일에 대한 인식 제고 - 청년층 참여 제고를 위해 사회적 대화를 축제 형식으로 기획·추진 ㅇ 재외동포 사회 등과 협업, 해외지역 통일문화 행사 개최 - K-문화를 소재로 한반도 평화 및 통일에 대한 공감대 확산, 통일 공공외교 확대 차원에서 민주평통 등 협업 기관 발굴 지속 □ 북한자료 대국민 서비스 확대 ㅇ 북한 정보 공개범위 확대 및 북한자료의 접근성‧편의성 제고 - AI‧빅데이터 기술을 활용한 ｢북한정보포털｣로 개편, 전자자료 제공 - 북한 특수자료의 적법한 활용을 위한 관리 강화 ㅇ ｢통일정보자료센터｣ 착공(’23.9월 고양), ‘북한정보의 메카’ 구축 - 북한‧통일 도서관‧사료관‧복합 문화공간 역할 수행 ㅇ 북한신문‧방송 등 단계적 개방 - 관계부처 협의를 바탕으로 우선 노동신문 시범공개 추진 - 지역통일관 등 열람 가능 장소 확대 󰊷 대내외 통일 역량 및 기반 강화 □ 남북협력기금의 민간 기부 적립 근거 마련 ㅇ 실향민 등 민간 기부자가 기탁한 민간 기부금을 적립·사용하기 위한 ｢남북협력기금법｣ 개정 추진 - 남북교류 활성화 단계 및 통일 이후 사용을 희망하며 기탁한 민간 기부 관련 별도 계정 설치, 적립근거 마련(정부 재정 소요 불필요) * 현행 남북협력기금은 단년도 편성방식으로, 통일 이후 사용 희망 기부금은 회계연도 경과 시 전액 기금 수입으로 귀속 불가피 ㅇ 전문가 의견수렴(~’23.1월) → 개정안 마련(~’23.2월) → 법제화(’23.3월~) 등 절차 추진 검토 □ 제1호 권역별 ｢통일+센터｣ 개관(’23.9, 목포) ㅇ ｢통일+센터｣를 중심으로 통일인프라 연계‧통합 운영 - 지역통일관, 하나센터 등 지역 인프라를 ｢통일+센터｣에 연계‧통합, 종합적 통일행정 서비스 제공 * 지역사회 여러 주체의 의견 수렴을 거쳐 최적의 방안을 마련·시행 ㅇ ’26년까지 권역별 ｢통일+센터｣ 구축 완료 * ’18년 인천(시범), ’23년 호남, ’24~''25년 강원·경기·충청, ''26년 영남·제주 개소 추진 □ 통일‧통합 관련 국제협력 강화 ㅇ 독일‧베트남, EU‧아세안 등의 통일‧통합 정책사례 연구 - ‘한독통일자문위원회’(5~6월, 베를린)를 통한 독일통일 경험 공유 - 베트남의 역사적 경험 공유를 위한 협력 추진 등 ㅇ 정전 70주년 계기 통일 문제 관련 ｢한반도 국제포럼｣ 서울 개최 - 미국 등 주요국 및 국제사회 대상 한반도 문제 및 우리 통일‧대북정책에 대한 관심 환기 계기로 적극 활용','2023-03-06','','230127 (붙임) 2023년 통일부 주요업무 추진계획.pdf [359KB]','',1,84,'2023-03-06 00:00:00','2023-03-06 00:00:00');
