INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','2021년 7월 9일 73회 조찬간담회 한국인터넷진흥원 이원태 원장님 강연자료','2021 년 7 월 9 일에 개최된 , 제 73 회 동북아공동체 ICT 포럼 조찬간담회에서 강연해주신 한국인터넷진흥 원 이원태 원님 및 참석해주신 많은분들께 감사드립니다 . "코로나19 이후 언택트 시대 사이버 보안','2021 년 7 월 9 일에 개최된 , 제 73 회 동북아공동체 ICT 포럼 조찬간담회에서 강연해주신 한국인터넷진흥 원 이원태 원님 및 참석해주신 많은분들께 감사드립니다 . "코로나19 이후 언택트 시대 사이버 보안 위협의 양상과 대응방향"이 라는 주제로 이승율 총장님께서 유익한 강연을 진행해 주셨습니다 . 본 게시물에 강의자료를 첨부하니 참고부탁드립니다 . 이후 제 73 차 조찬간담회에도 많은 관심과 참여 부탁드립니다 . * 파일이 저장되지 않을 시 첨부파일위에 마우스 커서를 올리시고 오른쪽 클릭 후 다른이름으로 대상저장을 하시면 저장이 완료됩니다 . 파일 크기로 인해 링크 연결이 안되는 경우 아래 메일 주소로 연락주시면 송부해드리도록 하겠습니다 . * 다운받기를 원하시는 분은 준회원 가입 후 정회원 등업신청을 아래로 하여주시기 바랍니다 . - 이메일 : bismak0308@naver.com - 전화 : 02-521-8171','2021-07-19','','\73회 조찬간담회 발표자료 게시용(이원태 원장님).pdf [8126KB]','',1,80,'2021-07-19 00:00:00','2021-07-19 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[남북협회 웹진 이음(94호) 바이든 정부의 대북정책과 북미관계 전망]','남북지원협회 웹진 '' 이음 '' 으로 연결됩니다 . http://webzine.sonosa.or.kr/202107 [ 남북협회 웹진 이음 (94 호 ) 바이든 정부의 대북정책과 북미관계 전망 ] 01 이달의 이야기 커','남북지원협회 웹진 '' 이음 '' 으로 연결됩니다 . http://webzine.sonosa.or.kr/202107 [ 남북협회 웹진 이음 (94 호 ) 바이든 정부의 대북정책과 북미관계 전망 ] 01 이달의 이야기 커버스토리 – 판문점 특집 – 바이든 정부의 대북정책과 북미관계 전망 외 02 포커스 온 현장스케치 – 3 개의 線 을 넘어 가본 ‘ 판문점 ’ 내 친구를 소개합니다 - 개성공업지구지원재단 03 정보마당 NK Trend 1 - 북한 경제 · 대외무역 동향 NK Trend 2 – 대북인도개발협력 동향 이달의 읽을거리 – 대한민국 평화기행 외 04 소통마당 SONOSA NEWS – 남북협회 소식을 전해드립니다 참여마당 – < 판문점 > 삼행시 !','2021-07-05','','','',1,79,'2021-07-05 00:00:00','2021-07-05 00:00:00');
