INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제71회 조찬간담회','2021년 2월 24일에 개최된 제71회 동북아공동체ICT포럼 조찬간담회 겸 정기총회에서 강연해주신 통일부 서호 차관님과 참석해주신 많은분들께 감사드립니다. "한반도 정세와 남북 관계 추진 방안"이라는 주제로 서호 ','2021년 2월 24일에 개최된 제71회 동북아공동체ICT포럼 조찬간담회 겸 정기총회에서 강연해주신 통일부 서호 차관님과 참석해주신 많은분들께 감사드립니다. "한반도 정세와 남북 관계 추진 방안"이라는 주제로 서호 차관님께서 유익한 강연을 진행해 주셨습니다. https://www.etnews.com/20210224000156 이 웹사이트는 서호 차관님이 강영하신 기사입니다. 링크에 들어가셔서 확인 바랍니다.','2021-02-25','','','',1,68,'2021-02-25 00:00:00','2021-02-25 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[ET단상]바이든 정부의 출범과 남북관계 기대감','자세한 내용은 https://www.etnews.com/20210120000195 를 타고 확인하시길 바랍니다. 조 바이든 정부 출범으로 미국 외교안보정책이 크게 변화할 것으로 예상된다 . 도널드 트럼프 정부의 미국','자세한 내용은 https://www.etnews.com/20210120000195 를 타고 확인하시길 바랍니다. 조 바이든 정부 출범으로 미국 외교안보정책이 크게 변화할 것으로 예상된다 . 도널드 트럼프 정부의 미국 우선주의는 폐기되고 미국 주도의 국제주의로 전환이 전망된다 . 이는 세계 최강국 미국이 국제질서 유지에 지도력을 발휘할 것이며 , 이것이 자국 이익에도 도움이 된다는 의미이다 . 한반도와 남북관계에 대한 영향도 불가피할 것으로 보인다 . 먼저 한미 관계에서 주한미군 축소 또는 철수 , 주둔비용 분담 문제 등 한반도 문제의 불확실성은 해소될 가능성이 짙다 . 그 대신 한미동맹을 강조하면서 대중대북 문제에는 한미 공동 대응을 요구할 것으로 예상된다 . 북미 문제 , 특히 북핵문제는 바이든 정부에서도 외교안보정책의 우선순위가 될 공산이 높다 . 그러나 트럼프 대통령의 세 차례에 걸친 북미 정상회담 등 톱다운 방식 협상은 중단될 것이다 . 그렇다고 빌 클린턴 정부의 대북포용 정책이나 버락 오바마 정부의 인내 전략 정책으로 회귀하지도 않을 것이다 . 바이든 정부의 대북전략은 선 북핵 위험 감소 , 대북 제재 전략 운용 , 다자간 국제협력 강화를 추진할 것으로 예상된다 . 또 이란식 해법 , 즉 핵무기 개발 억제와 국제 사찰을 대가로 하여 경제 제재 완화로 이어지는 다자간 협상을 북한에도 적용할 것이다 . 다만 바이든 정부는 트럼프 정부와 달리 실무협의 없는 정상회담은 하지 않을 것으로 예상된다 . 즉 보텀업으로 준비된 협상을 통해 단계별 스몰딜을 추진하며서 궁극으로 완전한 비핵화를 추구할 것으로 보인다 . 그러나 현 단계에서는 북한 핵 동결 , 즉 핵 확산과 고도화 방지가 우선 목표가 될 것으로 보인다 . 북한의 핵 확대와 미국의 추가 대북 제재는 서로 맞물려 있다고 할 수 있다 . 출처: 전자신문','2021-01-21','','','',1,67,'2021-01-21 00:00:00','2021-01-21 00:00:00');
