INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[제17회 데이터 컨퍼런스 안내] "데이터거버넌스 기반 데이터 거래·유통 플랫폼"','안녕하세요. 데이터스트림즈입니다. 다름이 아니오라, 오는 11월 26일 개최되는 '' 제17회 2020 DATA Conference'' (주최: 컴퓨터월드/IT Daily)에서 데이터스트림즈가 "데이터거버넌스 기반 데이','안녕하세요. 데이터스트림즈입니다. 다름이 아니오라, 오는 11월 26일 개최되는 '' 제17회 2020 DATA Conference'' (주최: 컴퓨터월드/IT Daily)에서 데이터스트림즈가 "데이터거버넌스 기반 데이터 거래·유통 플랫폼"라는 주제로 2번째 키노트 세션 에 참가하여 과기부 주관 ''빅데이터 플랫폼 및 센터 구축'' 사업의 교통/헬스케어/산림/유통 등 4개 분야 에서 빅데이터 플랫폼 및 데이터거래소를 구축한 사례 를 발표 할 예정입니다. 오후 Track2 세션 에서는 빅데이터 패브릭 전략 에 대해서도 소개하며, 전시 부스 도 운영 할 계획입니다. 이에 안내 e-DM을 송부드리오니, 고객 여러분들의 많은 관심을 부탁드립니다. 사전 참가 신청을 희망하시거나, 행사와 관련해 궁금한 사항이 있으신 분들은 아래 메일 주소를 통해 연락 부탁드립니다. (데이터스트림즈 마케팅팀, marketing@datastreams.co.kr)','2020-11-18','','','',1,61,'2020-11-18 00:00:00','2020-11-18 00:00:00');
