INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','(7월 22일 조찬간담회) 조명희 국회의원님 발표 강연자료','2020 년 7 월 22 일에 개최된 제 69 회 동북아공동체 ICT 포럼 조찬간담회에서 강연해주신 조명희 국회의원님 및 참석해주신 많은분들께 감사드립니다 . "비대면 시대의 극복을 위한 위성 및 공간정보의 역할과 ','2020 년 7 월 22 일에 개최된 제 69 회 동북아공동체 ICT 포럼 조찬간담회에서 강연해주신 조명희 국회의원님 및 참석해주신 많은분들께 감사드립니다 . "비대면 시대의 극복을 위한 위성 및 공간정보의 역할과 비전 " 이라는 주제로 조명희 국회의원님께서 유익한 강연을 진행해 주셨습니다 . 강의자료를 첨부하니 참고하시기 바랍니다 . 올해 9월에 있을 제 70 차 조찬간담회에도 많은 관심과 참여 부탁드립니다 . * 파일이 저장되지 않을 시 첨부파일 (\20200722.pdf) 위에 마우스 커서를 올리시고 오른쪽 클릭 후 다른 이름으로 대상저장을 하시면 저장이 완료됩니다 . 파일 크기로 인해 링크 연결이 안되는 경우 아래 메일 주소로 연락주시면 송부해드리도록 하겠습니다 . * 다운받기를 원하시는 분은 준회원 가입 후 정회원 등업신청을 아래로 하여주시기 바랍니다 . - 이메일 : bismak0308@naver.com - 전화 : 02-521-8171','2020-07-27','','\20200722.pdf [18993KB]','',1,54,'2020-07-27 00:00:00','2020-07-27 00:00:00');
