INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','2019년 4월 11일 조찬간담회 이효성 방통위원장 강연자료','지난 4월 11일 개최된, 제 64회 동북아공동체ICT포럼 조찬간담회에서 강연해주신 방송통신위원회 이효성 위원장님 및 참석해주신 많은 분들께 감사드립니다. "소통" 이라는 주제로 이효성 위원장님께서 유익한 강연을 진','지난 4월 11일 개최된, 제 64회 동북아공동체ICT포럼 조찬간담회에서 강연해주신 방송통신위원회 이효성 위원장님 및 참석해주신 많은 분들께 감사드립니다. "소통" 이라는 주제로 이효성 위원장님께서 유익한 강연을 진행해 주셨습니다. 본 게시물에 강의자료를 첨부하니 참고부탁드립니다. 이번 6월 19일에 있을 제 65회 조찬간담회에도 많은 관심과 참여 부탁드립니다. *파일이 저장되지 않을 시 첨부파일(20181122.pptx)위에 마우스 커서를 올리시고 오른쪽 클릭 후 다른이름으로 대상저장을 하시면 저장이 완료됩니다. 파일 크기로 인해 링크 연결이 안되는 경우 아래 메일 주소로 연락주시면 송부해드리도록 하겠습니다. *다운받기를 원하시는 분은 준회원 가입 후 정회원 등업신청을 아래로 하여주시기 바랍니다. -이메일: bismak0308@naver.com -전화: 02-521-8171','2019-06-03','','\190411.pptx [122KB]','',1,52,'2019-06-03 00:00:00','2019-06-03 00:00:00');
