INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[지경부 보도자료] 네트워크장비 新시장에서 글로벌 업체에 도전장','네트워크장비 新시장에서 글로벌 업체에 도전장 -「it 네트워크장비산업 발전전략 」 마련 - - 네트워크 구축시 사전설계심사 의무화 및 기술평가 대폭확대로 공정거래 유도 - - 네트워크 cpu 본격개발 등 핵심기술개발','네트워크장비 新시장에서 글로벌 업체에 도전장 -「it 네트워크장비산업 발전전략 」 마련 - - 네트워크 구축시 사전설계심사 의무화 및 기술평가 대폭확대로 공정거래 유도 - - 네트워크 cpu 본격개발 등 핵심기술개발 - □ 지식경제부는 8월 18일 위기관리대책회의에서 “it 네트워크장비산업 발전전략 ”을 보고하고, 네트워크장비 및 관련 부품산업 육성을 통한 2015년 新인터넷장비 주요생산국 도약방안 발표 □ it 네트워크장비산업은 스위치, 라우터, wi-fi, wibro 등 통신 및 인터넷 서비스 제공 에 필요한 장비 와 관련 된 산업 으로 ㅇ 인터넷 백본 시스템, 이동통신망 시스템, 사설망 시스템, ict플랜트 시스템, 가입자망 시스템 등으로 구성 □ 금번에 마련한 “it 네트워크장비산업 발전전략”에서 정부는 ▲ 내수 시장의 합리적인 생태계조성 , ▲명품 ict 솔루션 확보, ▲新인터넷 장비 글로벌 시장진출 지원, ▲글로벌 스타기업 육성 등 4대 전략 제시 ㅇ 정부는 먼저 정보화사업시 특정업체에 유리한 규격발주를 방지하여 공정거래를 유도 하고 중소기업의 적정이윤을 보장 하기 위하여 - 공공부문 에 대하여 기본설계서의 사전설계심사 의무화 제도를 도입 하고, 기술평가비중 을 90으로 대폭 상향조정 (기존 80) , 유명무실한 유지보수비용을 현실화 (10~15%) 하기로 하였음 * 붙임 : 보도자료 전문 100817102925_0817 (18일9시) 정보통신산업과, IT 네트워크장비산업 발전전략.hwp (142336) 100817102923_0817 (18일9시) 정보통신산업과, IT 네트워크장비산업 발전전략(안건).hwp (1533440)','2011-09-27','','','',1,46,'2011-09-27 00:00:00','2011-09-27 00:00:00');
