INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제249호','남북경협소식지 제249호 (2011.7.1.일자) [바로가기 클릭] < 개성공단 소식 > - 개성공단 월 생산액 3 천만 달러 유지 - 개성공단 생산제품 수출비중 9% - “ 한미 FTA 발효돼도 개성공단 제품 수입','남북경협소식지 제249호 (2011.7.1.일자) [바로가기 클릭] < 개성공단 소식 > - 개성공단 월 생산액 3 천만 달러 유지 - 개성공단 생산제품 수출비중 9% - “ 한미 FTA 발효돼도 개성공단 제품 수입 안 돼 ” < 남북경협 소식 > - “ 남북교역 , 재개 땐 제대로 ” - 남북 금강산 ‘ 재산정리 ’ 협의 - 2015U 대회 남북단일팀 구성 법적근거 마련 < 북한경제 소식 > - “ 북중교역 가속화 , 34 억 달러 규모 ” - “ 북 주민 하루 식량배급 190g 으로 줄어 ” < 기타소식 > - “ 북 , 3 년내 플루토늄보다 HEU 더 많이 보유 ” - 김성환 외교 “ 한미 , 남북대화 선행입장 재확인 ” - 북한 - 러시아 정상회담 취소된 듯','2011-07-04','','','',1,43,'2011-07-04 00:00:00','2011-07-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제248호','남북경협소식지 제248호 (2011.6.15.일자) [바로가기 클릭] <개성공단 소식> - 남북관계 ‘꽁꽁’, 개성공단 생산 증가 왜? - 인천시, 개성공단 물품전시회 개최 <남북경협 소식> - 통일부, 남북관계 상','남북경협소식지 제248호 (2011.6.15.일자) [바로가기 클릭] <개성공단 소식> - 남북관계 ‘꽁꽁’, 개성공단 생산 증가 왜? - 인천시, 개성공단 물품전시회 개최 <남북경협 소식> - 통일부, 남북관계 상황대비 위기관리팀 신설 - 북한, 현대 금강산관광 독점 제한법 제정 - 인천-개성-해주 남북 삼각벨트로 연결 <북한 경제 소식> - 북·중 합작개발 황금평 대규모 착공식 - 금강산 중국 관광객 월100~200명에 그쳐 - WFP, 5월 대북식량지원 규모 4월보다 줄어 <기타 소식> - 북한, 지난주 단거리 미사일 발사 - 대북 인도지원 촉구 ‘대화와 소통’ 발족 - 외교부 “북한, 국제사회 바람에 어긋나” <참고자료> - 북핵해결과 6자회담: 현실과 과제','2011-06-16','','','',1,42,'2011-06-16 00:00:00','2011-06-16 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제247호','남북경협소식지 제247호 (2011.6.1.일자) [바로가기 클릭] <개성공단 소식> - 5·24조치에도 개성공단 ‘호조’ - 경기의료원 파주병원, 개성공단서 의료봉사 <남북경협 소식> - 통일부 “남북 교역업체 대','남북경협소식지 제247호 (2011.6.1.일자) [바로가기 클릭] <개성공단 소식> - 5·24조치에도 개성공단 ‘호조’ - 경기의료원 파주병원, 개성공단서 의료봉사 <남북경협 소식> - 통일부 “남북 교역업체 대출금 상환유예 검토” - 통일부, 남북교역대금 결제 전담 은행 선정 - “천안함 사건과 남북경협 분리대응해야” <북한경제 소식> - 작년 북·중 교역 사상최대 기록 - 미국, 대북 식량지원 결정 3~4주 더 걸릴 것 <기타 소식> - 김정일 전격 방중 - 현인택 “남북대화, ‘선 사과 원칙’ 고수할 것” <참고자료> 북한경제의 현황 평가와 미래 전망','2011-06-02','','','',1,41,'2011-06-02 00:00:00','2011-06-02 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제246호','남북경협소식지 제246호 (2011.5.16.일자) [바로가기 클릭] <개성공단 소식> - 개성공단 체류인원 600명대로 확대 - 개성공단 위기상황시 정부가 입주기업에 통보 <남북경협 소식> - 개성공단 제품 ‘원산','남북경협소식지 제246호 (2011.5.16.일자) [바로가기 클릭] <개성공단 소식> - 개성공단 체류인원 600명대로 확대 - 개성공단 위기상황시 정부가 입주기업에 통보 <남북경협 소식> - 개성공단 제품 ‘원산지 논란’ - 중국 금강산관광 7월 재개 - 인천시, 대북 지원사업 이달 재개 <북한 경제 소식> - 북한 대중국 광물수출 8년 사이 17배 ‘껑충’ - 속도 못 내는 북·중 황금평 개발 - 북한 춘궁기 도래, 쌀값 급등 <기타 소식> - 핵전문가들 “북 경수로 사고위험 우려” - 남북 백두산 화산 학술토론회 끝내 무산 - “북한 외화벌이용 아편생산 대폭 확대” <참고자료> - 후쿠시마 원전사태 이후, 북핵문제 어떻게 접근해야 하는가','2011-05-16','','','',1,40,'2011-05-16 00:00:00','2011-05-16 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제245호','남북경협소식지 제245호 (2011.5.2.일자) [바로가기 클릭] <개성공단 소식> - 중진공, 개성공단 법인장 경영아카데미 실시 <남북경협 소식> - 북한 개성공단 제품, 한미FTA와 무관 - 북한의 금강산 독자','남북경협소식지 제245호 (2011.5.2.일자) [바로가기 클릭] <개성공단 소식> - 중진공, 개성공단 법인장 경영아카데미 실시 <남북경협 소식> - 북한 개성공단 제품, 한미FTA와 무관 - 북한의 금강산 독자 추진은 ''한시 조치'' - 경남 ''통일딸기'' 사업 중단위기 <북한경제 소식> - 북한, 지난해 광물수출 사상 최대 - NYT, "북한정권 경멸해도 주민 위한 식량 지원 필요" - 유니세프 대북사업 예산 70% 높아져 <기타 소식> - 남북 비핵화회담 급물살 탈까 - 북한 김정은 후계체제 구축 - 미국, 대북제재 새 행정명령 19일 발효 - 남북, 동해표기 협력 [참고자료] 중국의 한반도 전략과 역할','2011-05-04','','','',1,39,'2011-05-04 00:00:00','2011-05-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제244호','남북경협소식지 제244호 (2011.4.15일자) [바로가기 클릭] <개성공단 소식> - 개성공단 출입경, 21회에서 23회로 확대 <남북경협 소식> - 남북관계 경색에도 경협대출은 증가세 - 현대그룹 북한 관광독점','남북경협소식지 제244호 (2011.4.15일자) [바로가기 클릭] <개성공단 소식> - 개성공단 출입경, 21회에서 23회로 확대 <남북경협 소식> - 남북관계 경색에도 경협대출은 증가세 - 현대그룹 북한 관광독점권 취소 - 통일부, 민간단체 북한접촉 불허 방침 <북한 경제 소식> - 급물살 타는 북·중 경협 - 북한 자원 휩쓰는 ‘블랙홀’ 중국 - 탈북자들, ‘북한 식량사정 심각’ 증언 <기타 소식> - 북한 최고인민회의 개최 - 북한, “미 대북적대정책 심화할수록 핵 억제력 강화할 것” - 제2차 남북 백두산 화산협의 [참고자료] 후계구도하 북한 경제체제의 변화 전망','2011-04-18','','','',1,38,'2011-04-18 00:00:00','2011-04-18 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제243호','남북경협소식지 제243호 (2011.4.1일자) [바로가기 클릭] <개성공단 소식> - 개성공단 월생산액 3천만 달러 회복 - 개성공단 입주기업에 남북경협보험금 첫 지급 <남북경협 소식> - 무역협회 “남북교역, 북','남북경협소식지 제243호 (2011.4.1일자) [바로가기 클릭] <개성공단 소식> - 개성공단 월생산액 3천만 달러 회복 - 개성공단 입주기업에 남북경협보험금 첫 지급 <남북경협 소식> - 무역협회 “남북교역, 북중교역의 절반 수준” - 대북지원단체 문 닫을 위기 - 통일부, 이산가족 8만2000명 실태조사 <북한 경제 소식> - 북한 경제대표단, 미국 서부서 자본주의 경제 체험 - 현인택, “북한 경제·사회적 불안정 커져” - 중단위기 WFP대북사업 9백만 달러 수혈 <기타 소식> - 북한 내달 7일 최고인민회의 소집 - 남북, 백두산화산 민간 협의 개최 - 북한 구제역 계속 확산 <참고자료> [천안함 1주기]향후 대북정책 추진 방향','2011-04-01','','','',1,37,'2011-04-01 00:00:00','2011-04-01 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제242호','남북경협소식지 제242호 (2011.3.18일자) [바로가기 클릭] <개성공단 소식> - 북한, 개성공단 한국제품 단속 강화 - 독일 예술가 개성공단에서 셔츠 제작 <남북경협 소식> - 인천시-인천대 남북경협아카데미','남북경협소식지 제242호 (2011.3.18일자) [바로가기 클릭] <개성공단 소식> - 북한, 개성공단 한국제품 단속 강화 - 독일 예술가 개성공단에서 셔츠 제작 <남북경협 소식> - 인천시-인천대 남북경협아카데미 업무협약 - 남북경협 중단으로 북한 진출기업 위기 <북한 경제 소식> - 중국 물가인상에 북한 타격 - 외화난 타개에 나선 북한, 방법은? - 북ㆍ미 대화무드 형성되나 <기타 소식> - 북한 전자전 도발 감행 - 북 주민 27명 송환 합의 [참고자료] 북한의 변화와 통일 그리고 기업의 대응 전략 * 첨부: 남북경협소식지 제242호','2011-03-17','','','',1,36,'2011-03-17 00:00:00','2011-03-17 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제241호','남북경협소식지 제241호 (2011.3.2일자) [바로가기 클릭] 1. 개성공단 소식 - 남북관계 경색에도 개성공단 성적은 ''우수'' - 김정일생일, 개성공단 16~17일 휴무 2. 남북경협 소식 - 정부, 남북교류협','남북경협소식지 제241호 (2011.3.2일자) [바로가기 클릭] 1. 개성공단 소식 - 남북관계 경색에도 개성공단 성적은 ''우수'' - 김정일생일, 개성공단 16~17일 휴무 2. 남북경협 소식 - 정부, 남북교류협력법 위반 과태료 구체화 - 북한, 입주기업에 개성공단 회담 성원 촉구 - 북한이 우회진출 한국기업에 수익 송금한 까닭은 3. 북한경제 소식 - 북·중 경제협력 가속화 - 주요국들의 ''대북식량지원'' 재개될까 4. 기타 소식 - 대북심리전에 강경모드 돌입한 북한 - 북한, 3월 춘궁기에 남북대화 제의가능성 5. 참고자료 - 중국과 손잡은 북한, 점차 높아지는 대중의존도','2011-03-03','','','',1,35,'2011-03-03 00:00:00','2011-03-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제240호','남북경협소식지 제240호 (2011.2.16일자) [바로가기 클릭] 1. 개성공단 소식 - 개성에 ''봄''은 오나 - 북한 구제역 발생, 개성공단 출입 검역 강화 - 개성공단의 오염도는? 2. 남북경협 소식 - 대북 ','남북경협소식지 제240호 (2011.2.16일자) [바로가기 클릭] 1. 개성공단 소식 - 개성에 ''봄''은 오나 - 북한 구제역 발생, 개성공단 출입 검역 강화 - 개성공단의 오염도는? 2. 남북경협 소식 - 대북 인도적지원 재개 되나 ·북한 민화협, 대북지원연합체 방북 초청장 ·미의원 "대북식량지원 모니터링 전제돼야" 3. 북한경제 소식 - 북한 대외무역 50%이상 중국 의존 - 대중의존도 높아지는 北, 향후 향방은? - 中연변, 통행증 발급 재개에 北관광 급증 - 탈북자 50% 北에 송금 4. 기타 소식 - 北 ''제3국 비밀접촉'' 제의했었다 - 北 이르면 올해 말 3차 핵실험 가능 - 北 식량난 속에 김정일 생일 축제 준비','2011-03-02','','','',1,34,'2011-03-02 00:00:00','2011-03-02 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','남북경협소식지 제236호','남북경협소식지 제 236 호 (2010.12.16 일자 ) (바로가기 클릭)(/a) 1. 개성공단 소식 - 연평도 도발 이후 개성공단 기업 차량 첫 방북 - 개성공단 북한근로자 연평도발 후 700 명 증가 2. 남북','남북경협소식지 제 236 호 (2010.12.16 일자 ) (바로가기 클릭)(/a) 1. 개성공단 소식 - 연평도 도발 이후 개성공단 기업 차량 첫 방북 - 개성공단 북한근로자 연평도발 후 700 명 증가 2. 남북경협 소식 - 정부 , 11 개 금강산협력업체에 43 억원 대출 3. 북한경제 소식 - 올해 북한 김정일 현지지도 경제활동에 치중 - 북 , 개혁파 박봉주 전 내각총리 복귀 - 북중경협 틀어졌나 , 곳곳서 불협화음 감지 4. 기타 소식 - 북 주민 , 남한 법원서 친자소송 첫 승소 - 국제형사재판소 연평도 · 천안함 도발 , 전쟁범죄 조사 - 북 , 삼성 · LG 등 '' 한국산 전자 제품 '' 인기 - 북 우라늄시설 '' 커지는 의혹 '' - 탈북자 실업률 9.2%.. 경제활동 상태 열악','2010-12-17','','','',1,33,'2010-12-17 00:00:00','2010-12-17 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','중소기업진흥공단 남북경협소식지 제233호','남북경협소식지 제 233 호 (2010.11.1 일자 ) (바로가기 클릭)(/a) 1. 개성공단 소식 - ‘ 꿈의 직장 ’ 개성공단 , 임금 최대 100 배 - 개성공단 생산액 5 개월 만에 증가 2. 남북경협 소식','남북경협소식지 제 233 호 (2010.11.1 일자 ) (바로가기 클릭)(/a) 1. 개성공단 소식 - ‘ 꿈의 직장 ’ 개성공단 , 임금 최대 100 배 - 개성공단 생산액 5 개월 만에 증가 2. 남북경협 소식 - 남북 항공 관제 통신망 재가동 - ‘ 경영난 ’ 대북투자기업 등에 120 억원 대출 지원 - 수출입銀 , 올해 남북협력기금 417 억원 지원 3. 북한경제 소식 - 北시ㆍ도 책임비서 , 단체 방중 … 경제 협력 논의 - 北 , 올해 식량 100 만 t 부족 - '' 남북합작 '' 평양과기대 25 일 정식 개교 4. 기타 소식 - 北 , 주중 대사 6 개월만에 전격 교체 - 제 18 차 남북 이산가족 상봉 5. 참고자료 - " 상봉 정례화 " Vs " 쌀 . 비료지원 , 금강산관광 재개 "','2010-11-02','','','',1,32,'2010-11-02 00:00:00','2010-11-02 00:00:00');
