INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('member','김현 대한변호사협회 협회장 취임','본 포럼 김현 회원님의 제49대 대한변호사협회 협회장 취임을 진심으로 축하드립니다. [출처] 본 기사는 한국경제 에서 작성된 기사 입니다 원문 기사 보기: http://www.hankyung.com/news/app/','본 포럼 김현 회원님의 제49대 대한변호사협회 협회장 취임을 진심으로 축하드립니다. [출처] 본 기사는 한국경제 에서 작성된 기사 입니다 원문 기사 보기: http://www.hankyung.com/news/app/newsview.php?aid=201703134657i(강은구 기자)','2017-03-29','','','',1,21,'2017-03-29 00:00:00','2017-03-29 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('member','이상산 핸디소프트 대표 "SW 기술 융합 IoT 전문기업 도약"','[전자신문 2016.11.23] [오늘의 CEO] 이상산 핸디소프트 대표 "SW 기술 융합 IoT 전문기업 도약" 우리 포럼의 부회장이신 이상산 핸디소프트 사장님의 관련 기사입니다. 주식상장을 축하드립니다. [출처]','[전자신문 2016.11.23] [오늘의 CEO] 이상산 핸디소프트 대표 "SW 기술 융합 IoT 전문기업 도약" 우리 포럼의 부회장이신 이상산 핸디소프트 사장님의 관련 기사입니다. 주식상장을 축하드립니다. [출처] 본 기사는 전자신문에서 작성된 기사 입니다 원문 기사 보기: https://goo.gl/iSgHed (권동준기자 djkwon@etnews.com)','2016-11-24','','','',1,20,'2016-11-24 00:00:00','2016-11-24 00:00:00');
